  1→//! Browser automation tool for LLM agents.
  2→//!
  3→//! This tool provides full browser automation capabilities including:
  4→//! - Navigation with JavaScript execution
  5→//! - Screenshots of pages
  6→//! - DOM snapshots with numbered element references
  7→//! - Clicking, typing, scrolling on elements
  8→//! - JavaScript evaluation
  9→
 10→use {
 11→    crate::sandbox::SandboxRouter,
 12→    async_trait::async_trait,
 13→    moltis_agents::tool_registry::AgentTool,
 14→    moltis_browser::{BrowserManager, BrowserRequest},
 15→    std::{borrow::Cow, collections::HashMap, sync::Arc},
 16→    tokio::sync::{OnceCell, RwLock},
 17→    tracing::debug,
 18→};
 19→
 20→use crate::error::Error;
 21→
 22→/// Browser automation tool for interacting with web pages.
 23→///
 24→/// Unlike `web_fetch` which just retrieves page content, this tool allows
 25→/// full browser interaction: clicking buttons, filling forms, taking
 26→/// screenshots, and executing JavaScript.
 27→///
 28→/// This tool automatically tracks and reuses browser session IDs. When
 29→/// the LLM doesn't provide a session_id (or provides empty string), the
 30→/// tool will reuse the most recently created browser session for the current
 31→/// chat session. This prevents pool exhaustion without leaking browser state
 32→/// across unrelated chats.
 33→pub struct BrowserTool {
 34→    config: moltis_browser::BrowserConfig,
 35→    manager: OnceCell<Arc<BrowserManager>>,
 36→    sandbox_router: Option<Arc<SandboxRouter>>,
 37→    /// Track the most recent browser session ID per chat/session context.
 38→    /// This prevents pool exhaustion when the LLM forgets to pass session_id,
 39→    /// without reusing a stale browser across different chats.
 40→    /// Bounded to [`MAX_TRACKED_SESSIONS`] to prevent unbounded growth when
 41→    /// chats end without an explicit browser close action.
 42→    session_ids: RwLock<HashMap<String, String>>,
 43→}
 44→
 45→impl BrowserTool {
 46→    const DEFAULT_SESSION_KEY: &'static str = "main";
 47→    /// Maximum number of tracked browser sessions. When exceeded the oldest
 48→    /// entry (by insertion order, approximated by picking an arbitrary key) is
 49→    /// evicted to prevent unbounded memory growth from abandoned chats.
 50→    const MAX_TRACKED_SESSIONS: usize = 128;
 51→
 52→    /// Create a new browser tool from browser configuration.
 53→    pub fn new(config: moltis_browser::BrowserConfig) -> Self {
 54→        Self {
 55→            config,
 56→            manager: OnceCell::new(),
 57→            sandbox_router: None,
 58→            session_ids: RwLock::new(HashMap::new()),
 59→        }
 60→    }
 61→
 62→    /// Attach a sandbox router for per-session sandbox mode resolution.
 63→    pub fn with_sandbox_router(mut self, router: Arc<SandboxRouter>) -> Self {
 64→        self.sandbox_router = Some(router);
 65→        self
 66→    }
 67→
 68→    /// Create from config; returns `None` if browser is disabled.
 69→    pub fn from_config(config: &moltis_config::schema::BrowserConfig) -> Option<Self> {
 70→        if !config.enabled {
 71→            return None;
 72→        }
 73→        let browser_config = moltis_browser::BrowserConfig::from(config);
 74→        Some(Self::new(browser_config))
 75→    }
 76→
 77→    fn cache_key(session_key: Option<&str>) -> Cow<'static, str> {
 78→        match session_key {
 79→            Some(k) => Cow::Owned(k.to_string()),
 80→            None => Cow::Borrowed(Self::DEFAULT_SESSION_KEY),
 81→        }
 82→    }
 83→
 84→    /// Clear the tracked browser session for the current chat/session context
 85→    /// (e.g., after explicit close).
 86→    async fn clear_session(&self, session_key: &str) {
 87→        let mut guard = self.session_ids.write().await;
 88→        guard.remove(session_key);
 89→    }
 90→
 91→    /// Save the browser session ID for future reuse in the same chat/session
 92→    /// context.
 93→    async fn save_session(&self, session_key: &str, session_id: &str) {
 94→        if !session_id.is_empty() {
 95→            let mut guard = self.session_ids.write().await;
 96→            // Evict an arbitrary entry when at capacity to bound memory.
 97→            if guard.len() >= Self::MAX_TRACKED_SESSIONS
 98→                && !guard.contains_key(session_key)
 99→                && let Some(evict_key) = guard.keys().next().cloned()
100→            {
101→                debug!(evicted = %evict_key, "browser session cache full, evicting entry");
102→                guard.remove(&evict_key);
103→            }
104→            guard.insert(session_key.to_string(), session_id.to_string());
105→        }
106→    }
107→
108→    /// Get the tracked browser session ID for the current chat/session
109→    /// context, if available.
110→    async fn get_saved_session(&self, session_key: &str) -> Option<String> {
111→        let guard = self.session_ids.read().await;
112→        guard.get(session_key).cloned()
113→    }
114→
115→    async fn manager(&self) -> Arc<BrowserManager> {
116→        Arc::clone(
117→            self.manager
118→                .get_or_init(|| async {
119→                    let config = self.config.clone();
120→                    match tokio::task::spawn_blocking(move || {
121→                        // Browser detection/container cleanup can block.
122→                        moltis_browser::detect::check_and_warn(config.chrome_path.as_deref());
123→                        Arc::new(BrowserManager::new(config))
124→                    })
125→                    .await
126→                    {
127→                        Ok(manager) => manager,
128→                        Err(error) => {
129→                            tracing::warn!(
130→                                %error,
131→                                "browser tool warmup worker failed, falling back to inline initialization"
132→                            );
133→                            let config = self.config.clone();
134→                            moltis_browser::detect::check_and_warn(config.chrome_path.as_deref());
135→                            Arc::new(BrowserManager::new(config))
136→                        },
137→                    }
138→                })
139→                .await,
140→        )
141→    }
142→}
143→
144→#[async_trait]
145→impl AgentTool for BrowserTool {
146→    fn name(&self) -> &str {
147→        "browser"
148→    }
149→
150→    fn description(&self) -> &str {
151→        "Control a real browser to interact with web pages.\n\n\
152→         USE THIS TOOL when the user says 'browse', 'browser', 'open in browser', \
153→         or needs interaction (clicking, forms, screenshots, JavaScript-heavy pages).\n\n\
154→         REQUIRED: You MUST specify an 'action' parameter. Example:\n\
155→         {\"action\": \"navigate\", \"url\": \"https://example.com\"}\n\n\
156→         Actions: navigate, screenshot, snapshot, click, type, scroll, evaluate, wait, close\n\n\
157→         BROWSER CHOICE: optionally set \"browser\" to choose one (auto, chrome, chromium, \
158→         edge, brave, opera, vivaldi, arc). If no browser is installed, Moltis will try \
159→         to auto-install one.\n\n\
160→         SESSION: The browser session is automatically tracked per chat session. \
161→         After 'navigate', subsequent actions in the same chat will reuse the same \
162→         browser. No need to pass session_id.\n\n\
163→         WORKFLOW:\n\
164→         1. {\"action\": \"navigate\", \"url\": \"...\"} - opens URL in browser\n\
165→         2. {\"action\": \"snapshot\"} - get interactive elements with ref numbers\n\
166→         3. {\"action\": \"click\", \"ref_\": N} - click element by ref number\n\
167→         4. {\"action\": \"screenshot\"} - capture the current view\n\
168→         5. {\"action\": \"close\"} - close the browser when done"
169→    }
170→
171→    fn parameters_schema(&self) -> serde_json::Value {
172→        serde_json::json!({
173→            "type": "object",
174→            "required": ["action"],
175→            "properties": {
176→                "action": {
177→                    "type": "string",
178→                    "enum": ["navigate", "screenshot", "snapshot", "click", "type", "scroll", "evaluate", "wait", "get_url", "get_title", "back", "forward", "refresh", "close"],
179→                    "description": "REQUIRED. The browser action to perform. Use 'navigate' with 'url' to open a page, 'snapshot' to see elements, 'screenshot' to capture."
180→                },
181→                "session_id": {
182→                    "type": "string",
183→                    "description": "Browser session ID (omit to create new session, or reuse existing)"
184→                },
185→                "browser": {
186→                    "type": "string",
187→                    "enum": ["auto", "chrome", "chromium", "edge", "brave", "opera", "vivaldi", "arc"],
188→                    "description": "Browser to use for host mode. Default: auto (first installed browser)."
189→                },
190→                "url": {
191→                    "type": "string",
192→                    "description": "URL to navigate to (for 'navigate' action)"
193→                },
194→                "ref_": {
195→                    "type": "integer",
196→                    "description": "Element reference number from snapshot (for click/type/scroll)"
197→                },
198→                "text": {
199→                    "type": "string",
200→                    "description": "Text to type (for 'type' action)"
201→                },
202→                "code": {
203→                    "type": "string",
204→                    "description": "JavaScript code to execute (for 'evaluate' action)"
205→                },
206→                "x": {
207→                    "type": "integer",
208→                    "description": "Horizontal scroll pixels (for 'scroll' action)"
209→                },
210→                "y": {
211→                    "type": "integer",
212→                    "description": "Vertical scroll pixels (for 'scroll' action)"
213→                },
214→                "full_page": {
215→                    "type": "boolean",
216→                    "description": "Capture full page screenshot vs viewport only"
217→                },
218→                "selector": {
219→                    "type": "string",
220→                    "description": "CSS selector to wait for (for 'wait' action)"
221→                },
222→                "timeout_ms": {
223→                    "type": "integer",
224→                    "description": "Timeout in milliseconds (default: 60000)"
225→                }
226→            }
227→        })
228→    }
229→
230→    async fn execute(&self, params: serde_json::Value) -> anyhow::Result<serde_json::Value> {
231→        let mut params = params;
232→
233→        // Browser sandbox mode follows the session sandbox mode from the shared router.
234→        let session_key = Self::cache_key(params.get("_session_key").and_then(|v| v.as_str()));
235→        let sandbox_mode = if let Some(ref router) = self.sandbox_router {
236→            router.is_sandboxed(&session_key).await
237→        } else {
238→            debug!(
239→                session_key = %session_key,
240→                "browser running in host mode (no container backend)"
241→            );
242→            false
243→        };
244→
245→        // Inject saved session_id if LLM didn't provide one (or provided empty string)
246→        if let Some(obj) = params.as_object_mut() {
247→            let needs_session = match obj.get("session_id") {
248→                None => true,
249→                Some(serde_json::Value::String(s)) if s.is_empty() => true,
250→                Some(serde_json::Value::Null) => true,
251→                _ => false,
252→            };
253→
254→            if needs_session && let Some(saved_sid) = self.get_saved_session(&session_key).await {
255→                debug!(
256→                    session_key = %session_key,
257→                    session_id = %saved_sid,
258→                    "injecting saved session_id (LLM didn't provide one)"
259→                );
260→                obj.insert("session_id".to_string(), serde_json::json!(saved_sid));
261→            }
262→
263→            // Inject sandbox mode from session context
264→            obj.insert("sandbox".to_string(), serde_json::json!(sandbox_mode));
265→        }
266→
267→        // Check if this is a "close" action - we'll clear saved session after
268→        let is_close = params
269→            .get("action")
270→            .and_then(|a| a.as_str())
271→            .is_some_and(|a| a == "close");
272→
273→        // Try to parse the request, defaulting to "navigate" if action is missing
274→        let request: BrowserRequest = match serde_json::from_value(params.clone()) {
275→            Ok(req) => req,
276→            Err(e) if e.to_string().contains("missing field `action`") => {
277→                // Default to navigate action if action is missing but url is present
278→                if let Some(obj) = params.as_object_mut() {
279→                    if obj.contains_key("url") {
280→                        obj.insert("action".to_string(), serde_json::json!("navigate"));
281→                        serde_json::from_value(params)?
282→                    } else {
283→                        // No URL either - return helpful error
284→                        return Err(Error::message(
285→                            "Missing required 'action' field. Use: \
286→                             {\"action\": \"navigate\", \"url\": \"https://...\"} to open a page",
287→                        )
288→                        .into());
289→                    }
290→                } else {
291→                    return Err(e.into());
292→                }
293→            },
294→            Err(e) => return Err(e.into()),
295→        };
296→
297→        let manager = self.manager().await;
298→        let response = manager.handle_request(request).await;
299→
300→        // Track the session ID for future reuse
301→        if response.success {
302→            if is_close {
303→                self.clear_session(&session_key).await;
304→            } else {
305→                self.save_session(&session_key, &response.session_id).await;
306→            }
307→        }
308→
309→        Ok(serde_json::to_value(&response)?)
310→    }
311→
312→    async fn warmup(&self) -> anyhow::Result<()> {
313→        let started = std::time::Instant::now();
314→        let _ = self.manager().await;
315→        debug!(
316→            elapsed_ms = started.elapsed().as_millis(),
317→            "browser tool warmup complete"
318→        );
319→        Ok(())
320→    }
321→}
