362→    #[tokio::test]
363→    async fn saved_browser_sessions_are_scoped_by_chat_session() {
364→        let config = moltis_config::schema::BrowserConfig {
365→            enabled: true,
366→            ..Default::default()
367→        };
368→        let tool = BrowserTool::from_config(&config).unwrap();
369→
370→        tool.save_session("web:session:one", "browser-session-one")
371→            .await;
372→        tool.save_session("web:session:two", "browser-session-two")
373→            .await;
374→
375→        assert_eq!(
376→            tool.get_saved_session("web:session:one").await,
377→            Some("browser-session-one".to_string())
378→        );
379→        assert_eq!(
380→            tool.get_saved_session("web:session:two").await,
381→            Some("browser-session-two".to_string())
382→        );
383→        assert_eq!(tool.get_saved_session("web:session:three").await, None);
384→    }
385→
386→    #[tokio::test]
387→    async fn empty_session_id_is_not_saved() {
388→        let config = moltis_config::schema::BrowserConfig {
389→            enabled: true,
390→            ..Default::default()
391→        };
392→        let tool = BrowserTool::from_config(&config).unwrap();
393→        tool.save_session("web:session:one", "").await;
394→        assert_eq!(tool.get_saved_session("web:session:one").await, None);
395→    }
396→
397→    #[tokio::test]
398→    async fn session_cache_evicts_when_full() {
399→        let config = moltis_config::schema::BrowserConfig {
400→            enabled: true,
401→            ..Default::default()
402→        };
403→        let tool = BrowserTool::from_config(&config).unwrap();
404→
405→        // Fill the cache to capacity
406→        for i in 0..BrowserTool::MAX_TRACKED_SESSIONS {
407→            tool.save_session(&format!("session-{i}"), &format!("sid-{i}"))
408→                .await;
409→        }
410→        assert_eq!(
411→            tool.session_ids.read().await.len(),
412→            BrowserTool::MAX_TRACKED_SESSIONS
413→        );
414→
415→        // Adding one more should evict an entry and stay at capacity
416→        tool.save_session("session-new", "sid-new").await;
417→        let guard = tool.session_ids.read().await;
418→        assert_eq!(guard.len(), BrowserTool::MAX_TRACKED_SESSIONS);
419→        assert_eq!(guard.get("session-new"), Some(&"sid-new".to_string()));
420→    }
421→
422→    #[tokio::test]
423→    async fn clearing_one_chat_session_keeps_other_browser_sessions() {
424→        let config = moltis_config::schema::BrowserConfig {
425→            enabled: true,
426→            ..Default::default()
427→        };
428→        let tool = BrowserTool::from_config(&config).unwrap();
429→
430→        tool.save_session("web:session:one", "browser-session-one")
431→            .await;
432→        tool.save_session("web:session:two", "browser-session-two")
433→            .await;
434→
435→        tool.clear_session("web:session:one").await;
436→
437→        assert_eq!(tool.get_saved_session("web:session:one").await, None);
438→        assert_eq!(
439→            tool.get_saved_session("web:session:two").await,
440→            Some("browser-session-two".to_string())
441→        );
442→    }
443→}
