 34→/// Extract session_id or return an error for actions that require an existing session.
 35→fn require_session(session_id: Option<&str>, action: &str) -> Result<String, Error> {
 36→    session_id
 37→        .map(String::from)
 38→        .ok_or_else(|| Error::InvalidAction(format!("{action} requires a session_id")))
 39→}
