 41→/// Manage Chrome/Chromium instances with CDP.
 42→pub struct BrowserManager {
 43→    pool: Arc<BrowserPool>,
 44→    config: BrowserConfig,
 45→    screencasts: Arc<ScreencastRegistry>,
 46→}
 47→
 48→impl Default for BrowserManager {
 49→    fn default() -> Self {
 50→        Self::new(BrowserConfig::default())
 51→    }
 52→}
 53→
 54→impl BrowserManager {
 55→    /// Create a new browser manager with the given configuration.
 56→    pub fn new(config: BrowserConfig) -> Self {
 57→        match crate::container::cleanup_stale_browser_containers(&config.container_prefix) {
 58→            Ok(removed) if removed > 0 => {
 59→                info!(
 60→                    removed,
 61→                    "removed stale browser containers from previous runs"
 62→                );
 63→            },
 64→            Ok(_) => {},
 65→            Err(e) => {
 66→                warn!(error = %e, "failed to clean stale browser containers at startup");
 67→            },
 68→        }
 69→
 70→        info!(
 71→            sandbox_image = %config.sandbox_image,
 72→            "browser manager initialized (sandbox mode controlled per-session)"
 73→        );
 74→
 75→        Self {
 76→            pool: Arc::new(BrowserPool::new(config.clone())),
 77→            config,
 78→            screencasts: Arc::new(ScreencastRegistry::new()),
 79→        }
 80→    }
 81→
