 21→fn security_audit(event: &str, details: Value) {
 22→    let dir = moltis_config::data_dir().join("logs");
 23→    let path = dir.join("security-audit.jsonl");
 24→    let now_ms = std::time::SystemTime::now()
 25→        .duration_since(std::time::UNIX_EPOCH)
 26→        .unwrap_or_default()
 27→        .as_millis() as u64;
 28→    let line = serde_json::json!({
 29→        "ts": now_ms,
 30→        "event": event,
 31→        "details": details,
 32→    })
 33→    .to_string();
 34→
 35→    let _ = (|| -> std::io::Result<()> {
 36→        std::fs::create_dir_all(&dir)?;
 37→        let mut file = std::fs::OpenOptions::new()
 38→            .create(true)
 39→            .append(true)
 40→            .open(path)?;
 41→        use std::io::Write as _;
 42→        writeln!(file, "{line}")?;
 43→        Ok(())
 44→    })();
 45→}
