 47→async fn command_available(command: &str) -> bool {
 48→    tokio::process::Command::new(command)
 49→        .arg("--version")
 50→        .output()
 51→        .await
 52→        .map(|o| o.status.success())
 53→        .unwrap_or(false)
 54→}
