 56→async fn run_mcp_scan(installed_dir: &Path) -> anyhow::Result<Value> {
 57→    let mut cmd = if command_available("uvx").await {
 58→        let mut c = tokio::process::Command::new("uvx");
 59→        c.arg("mcp-scan@latest");
 60→        c
 61→    } else {
 62→        tokio::process::Command::new("mcp-scan")
 63→    };
 64→
 65→    cmd.arg("--skills")
 66→        .arg(installed_dir)
 67→        .arg("--json")
 68→        .stdout(std::process::Stdio::piped())
 69→        .stderr(std::process::Stdio::piped());
 70→
 71→    let output = tokio::time::timeout(std::time::Duration::from_secs(300), cmd.output())
 72→        .await
 73→        .map_err(|_| anyhow::anyhow!("mcp-scan timed out after 5 minutes"))??;
 74→
 75→    if !output.status.success() {
 76→        let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
 77→        anyhow::bail!(if stderr.is_empty() {
 78→            "mcp-scan failed".to_string()
 79→        } else {
 80→            format!("mcp-scan failed: {stderr}")
 81→        });
 82→    }
 83→
 84→    let stdout = String::from_utf8_lossy(&output.stdout).to_string();
 85→    let parsed: Value = serde_json::from_str(&stdout)
 86→        .map_err(|e| anyhow::anyhow!("invalid mcp-scan JSON output: {e}"))?;
 87→    Ok(parsed)
 88→}
