 96→fn commit_url_for_source(source: &str, sha: &str) -> Option<String> {
 97→    if sha.trim().is_empty() {
 98→        return None;
 99→    }
100→    if source.starts_with("https://") || source.starts_with("http://") {
101→        return Some(format!("{}/commit/{}", source.trim_end_matches('/'), sha));
102→    }
103→    if source.contains('/') {
104→        return Some(format!("https://github.com/{}/commit/{}", source, sha));
105→    }
106→    None
107→}
