109→fn license_url_for_source(source: &str, license: Option<&str>) -> Option<String> {
110→    let text = license?.to_ascii_lowercase();
111→    let file = if text.contains("license.txt") {
112→        "LICENSE.txt"
113→    } else if text.contains("license.md") {
114→        "LICENSE.md"
115→    } else if text.contains("license") {
116→        "LICENSE"
117→    } else {
118→        return None;
119→    };
120→
121→    if source.starts_with("https://") || source.starts_with("http://") {
122→        Some(format!(
123→            "{}/blob/main/{}",
124→            source.trim_end_matches('/'),
125→            file
126→        ))
127→    } else if source.contains('/') {
128→        Some(format!("https://github.com/{}/blob/main/{}", source, file))
129→    } else {
130→        None
131→    }
132→}
