134→fn local_repo_head_timestamp_ms(repo_dir: &Path) -> Option<u64> {
135→    let repo = gix::open(repo_dir).ok()?;
136→    let obj = repo.rev_parse_single("HEAD").ok()?;
137→    let commit = repo.find_commit(obj.detach()).ok()?;
138→    let secs = commit.time().ok()?.seconds;
139→    Some((secs as i128).max(0) as u64 * 1000)
140→}
141→
142→fn commit_age_days(commit_ts_ms: Option<u64>) -> Option<u64> {
143→    let ts = commit_ts_ms?;
144→    let now_ms = std::time::SystemTime::now()
145→        .duration_since(std::time::UNIX_EPOCH)
146→        .ok()?
147→        .as_millis() as u64;
148→    Some(now_ms.saturating_sub(ts) / 86_400_000)
149→}
