            ..Default::default()
        };
        let tool = BrowserTool::from_config(&config).unwrap();
        let schema = tool.parameters_schema();
        let required = schema["required"].as_array().unwrap();
        assert!(
            required.iter().any(|v| v == "action"),
            "action should be in required fields"
        );
    }

