//! Browser action types and request/response structures.

use std::fmt;

use serde::{Deserialize, Serialize};

/// Browser action to perform.
#[derive(Debug, Clone, Deserialize)]
#[serde(tag = "action", rename_all = "snake_case")]
pub enum BrowserAction {
    /// Navigate to a URL.
    Navigate { url: String },

    /// Take a screenshot of the current page.
    Screenshot {
        #[serde(default)]
        full_page: bool,
        /// Optional: highlight element by ref before screenshot.
        #[serde(default)]
        highlight_ref: Option<u32>,
    },

    /// Get a DOM snapshot with numbered element references.
    Snapshot,

    /// Click an element by its reference number.
    Click { ref_: u32 },

    /// Type text into an element.
    Type { ref_: u32, text: String },

    /// Scroll the page or an element.
    Scroll {
        /// Element ref to scroll (None = viewport).
        #[serde(default)]
        ref_: Option<u32>,
        /// Horizontal scroll delta.
        #[serde(default)]
        x: i32,
        /// Vertical scroll delta.
        #[serde(default)]
        y: i32,
    },

    /// Execute JavaScript in the page context.
    Evaluate { code: String },

    /// Wait for an element to appear (by CSS selector or ref).
    Wait {
        #[serde(default)]
        selector: Option<String>,
        #[serde(default)]
        ref_: Option<u32>,
        #[serde(default = "default_wait_timeout_ms")]
        timeout_ms: u64,
    },

    /// Get the current page URL.
    GetUrl,

    /// Get the page title.
    GetTitle,

    /// Go back in history.
    Back,

    /// Go forward in history.
    Forward,

    /// Refresh the page.
    Refresh,

    /// Close the browser session.
    Close,

    /// Start streaming screenshots of the page (CDP screencast).
    StartScreencast {
        /// JPEG quality 1-100 (default 60).
        #[serde(default = "default_screencast_quality")]
        quality: u8,
        /// Max width to downscale to (default 1280).
        #[serde(default = "default_screencast_max_width")]
        max_width: u32,
        /// Max height to downscale to (default 800).
        #[serde(default = "default_screencast_max_height")]
        max_height: u32,
    },

    /// Stop the screencast stream.
    StopScreencast,

    /// Send a mouse event directly to the browser page.
    MouseInput {
        /// X coordinate in CSS pixels.
        x: f64,
        /// Y coordinate in CSS pixels.
        y: f64,
        /// Mouse event type.
        event_type: MouseInputType,
        /// Mouse button (default: left).
        #[serde(default)]
        button: MouseInputButton,
        /// Click count (default: 1).
        #[serde(default = "default_click_count")]
        click_count: u32,
    },

    /// Send a keyboard event directly to the browser page.
    KeyboardInput {
        /// Keyboard event type.
        event_type: KeyInputType,
        /// Key identifier (e.g. "Enter", "a", "ArrowDown").
        #[serde(default)]
        key: Option<String>,
        /// Text to insert (for char/keyDown events).
        #[serde(default)]
        text: Option<String>,
        /// Physical key code (e.g. "KeyA", "Enter").
        #[serde(default)]
        code: Option<String>,
        /// Modifier bitmask: Alt=1, Ctrl=2, Meta=4, Shift=8.
        #[serde(default)]
        modifiers: Option<i64>,
    },

    /// Export cookies from the browser session.
    ExportCookies {
        /// Optional domain filter (e.g. "example.com").
        #[serde(default)]
        domain: Option<String>,
    },

    /// Import cookies into the browser session.
    ImportCookies {
        /// Cookies to set.
        cookies: Vec<CookieParam>,
    },
}

fn default_wait_timeout_ms() -> u64 {
    30000
}

fn default_screencast_quality() -> u8 {
    60
}

fn default_screencast_max_width() -> u32 {
    1280
}

fn default_screencast_max_height() -> u32 {
    800
}

fn default_click_count() -> u32 {
    1
}

/// Mouse event type for direct input.
#[derive(Debug, Clone, Copy, Deserialize)]
#[serde(rename_all = "camelCase")]
pub enum MouseInputType {
    #[serde(rename = "mousePressed")]
    Pressed,
    #[serde(rename = "mouseReleased")]
    Released,
    #[serde(rename = "mouseMoved")]
    Moved,
    #[serde(rename = "mouseWheel")]
    Wheel,
}

/// Mouse button for direct input.
#[derive(Debug, Clone, Copy, Default, Deserialize)]
#[serde(rename_all = "lowercase")]
pub enum MouseInputButton {
    #[default]
    Left,
    Right,
    Middle,
}

/// Keyboard event type for direct input.
#[derive(Debug, Clone, Copy, Deserialize)]
#[serde(rename_all = "camelCase")]
pub enum KeyInputType {
    KeyDown,
    KeyUp,
    Char,
}

/// Cookie parameter for import.
#[derive(Debug, Clone, Deserialize, Serialize)]
pub struct CookieParam {
    pub name: String,
    pub value: String,
    pub domain: Option<String>,
    pub path: Option<String>,
    #[serde(default)]
    pub secure: bool,
    #[serde(default)]
    pub http_only: bool,
    /// Expiry as Unix timestamp (seconds).
    pub expires: Option<f64>,
    #[serde(default)]
    pub same_site: Option<String>,
}

/// Exported cookie from the browser.
#[derive(Debug, Clone, Serialize)]
pub struct ExportedCookie {
    pub name: String,
    pub value: String,
    pub domain: String,
    pub path: String,
    pub secure: bool,
    pub http_only: bool,
    pub expires: f64,
    pub same_site: String,
    pub size: u32,
}

/// Known Chromium-family browser engines we can launch.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum BrowserKind {
    Chrome,
    Chromium,
    Edge,
    Brave,
    Opera,
    Vivaldi,
    Arc,
    Custom,
}

impl BrowserKind {
    pub fn as_str(self) -> &'static str {
        match self {
            Self::Chrome => "chrome",
            Self::Chromium => "chromium",
            Self::Edge => "edge",
            Self::Brave => "brave",
            Self::Opera => "opera",
            Self::Vivaldi => "vivaldi",
            Self::Arc => "arc",
            Self::Custom => "custom",
        }
    }
}

impl fmt::Display for BrowserKind {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.write_str(self.as_str())
    }
}

/// Preferred browser for a request.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize, Default)]
#[serde(rename_all = "snake_case")]
pub enum BrowserPreference {
    #[default]
    Auto,
    Chrome,
    Chromium,
    Edge,
    Brave,
    Opera,
    Vivaldi,
    Arc,
}

impl BrowserPreference {
    pub fn preferred_kind(self) -> Option<BrowserKind> {
        match self {
            Self::Auto => None,
            Self::Chrome => Some(BrowserKind::Chrome),
            Self::Chromium => Some(BrowserKind::Chromium),
            Self::Edge => Some(BrowserKind::Edge),
            Self::Brave => Some(BrowserKind::Brave),
            Self::Opera => Some(BrowserKind::Opera),
            Self::Vivaldi => Some(BrowserKind::Vivaldi),
            Self::Arc => Some(BrowserKind::Arc),
        }
    }
}

impl fmt::Display for BrowserPreference {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self.preferred_kind() {
            Some(kind) => kind.fmt(f),
            None => f.write_str("auto"),
        }
    }
}

impl fmt::Display for BrowserAction {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Self::Navigate { url } => write!(f, "navigate({})", url),
            Self::Screenshot { full_page, .. } => {
                if *full_page {
                    write!(f, "screenshot(full_page)")
                } else {
                    write!(f, "screenshot")
                }
            },
            Self::Snapshot => write!(f, "snapshot"),
            Self::Click { ref_ } => write!(f, "click(ref={})", ref_),
            Self::Type { ref_, .. } => write!(f, "type(ref={})", ref_),
            Self::Scroll { ref_, x, y } => match ref_ {
                Some(r) => write!(f, "scroll(ref={}, x={}, y={})", r, x, y),
                None => write!(f, "scroll(x={}, y={})", x, y),
            },
            Self::Evaluate { .. } => write!(f, "evaluate"),
            Self::Wait { selector, ref_, .. } => match (selector, ref_) {
                (Some(s), _) => write!(f, "wait(selector={})", s),
                (_, Some(r)) => write!(f, "wait(ref={})", r),
                _ => write!(f, "wait"),
            },
            Self::GetUrl => write!(f, "get_url"),
            Self::GetTitle => write!(f, "get_title"),
            Self::Back => write!(f, "back"),
            Self::Forward => write!(f, "forward"),
            Self::Refresh => write!(f, "refresh"),
            Self::Close => write!(f, "close"),
            Self::StartScreencast { .. } => write!(f, "start_screencast"),
            Self::StopScreencast => write!(f, "stop_screencast"),
            Self::MouseInput { x, y, .. } => write!(f, "mouse_input(x={x}, y={y})"),
            Self::KeyboardInput { key, text, .. } => match (key, text) {
                (Some(k), _) => write!(f, "keyboard_input(key={k})"),
                (_, Some(t)) => write!(f, "keyboard_input(text={t})"),
                _ => write!(f, "keyboard_input"),
            },
            Self::ExportCookies { domain } => match domain {
                Some(d) => write!(f, "export_cookies(domain={d})"),
                None => write!(f, "export_cookies"),
            },
            Self::ImportCookies { cookies } => {
                write!(f, "import_cookies(count={})", cookies.len())
            },
        }
    }
}

/// Request to the browser service.
#[derive(Debug, Clone, Deserialize)]
pub struct BrowserRequest {
    /// Browser session ID (optional - creates new if missing).
    #[serde(default)]
    pub session_id: Option<String>,

    /// The action to perform.
    #[serde(flatten)]
    pub action: BrowserAction,

    /// Global timeout in milliseconds.
    #[serde(default = "default_timeout_ms")]
    pub timeout_ms: u64,

    /// Whether to run in sandbox mode (Docker container).
    /// If None, uses host mode (no sandbox).
    #[serde(default)]
    pub sandbox: Option<bool>,

    /// Optional browser preference for host mode.
    /// - "auto" (default): first detected installed browser
    /// - specific browser ("brave", "chrome", etc): use that browser
    #[serde(default)]
    pub browser: Option<BrowserPreference>,
}

fn default_timeout_ms() -> u64 {
    60000
}

/// Element reference in a DOM snapshot.
#[derive(Debug, Clone, Serialize)]
pub struct ElementRef {
    /// Unique reference number for this element.
    pub ref_: u32,
    /// Tag name (e.g., "button", "input", "a").
    pub tag: String,
    /// Element's role attribute or inferred role.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub role: Option<String>,
    /// Visible text content (truncated).
    #[serde(skip_serializing_if = "Option::is_none")]
    pub text: Option<String>,
    /// Link href (for anchor elements).
    #[serde(skip_serializing_if = "Option::is_none")]
    pub href: Option<String>,
    /// Input placeholder.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub placeholder: Option<String>,
    /// Input value.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub value: Option<String>,
    /// aria-label attribute.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub aria_label: Option<String>,
    /// Whether the element is visible in the viewport.
    pub visible: bool,
    /// Whether the element is interactive (clickable/editable).
    pub interactive: bool,
    /// Bounding box in viewport coordinates.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub bounds: Option<ElementBounds>,
}

/// Bounding box for an element.
#[derive(Debug, Clone, Serialize)]
pub struct ElementBounds {
    pub x: f64,
    pub y: f64,
    pub width: f64,
    pub height: f64,
}

/// DOM snapshot with element references.
#[derive(Debug, Clone, Serialize)]
pub struct DomSnapshot {
    /// Current page URL.
    pub url: String,
    /// Page title.
    pub title: String,
    /// Page text content (body innerText, truncated).
    #[serde(skip_serializing_if = "Option::is_none")]
    pub content: Option<String>,
