  1→// ── Browser viewer page (Preact + HTM + Signals) ─────────
  2→//
  3→// Shows active browser sessions, lets users view the browser via
  4→// CDP screencast, send mouse/keyboard input, and manage sessions.
  5→
  6→import { signal } from "@preact/signals";
  7→import { html } from "htm/preact";
  8→import { render } from "preact";
  9→import { useEffect, useRef, useState } from "preact/hooks";
 10→import { onEvent } from "./events.js";
 11→import { showToast } from "./ui.js";
 12→
 13→var sessions = signal([]);
 14→var loading = signal(false);
 15→var activeSession = signal(null);
 16→var screencasting = signal(false);
 17→var frameData = signal(null);
 18→var frameMeta = signal(null);
 19→var frameSeq = signal(0);
 20→var containerEl = null;
 21→
 22→// ── API helpers ─────────────────────────────────────────────
 23→
 24→async function browserAction(params) {
 25→	var res = await fetch("/api/browser/action", {
 26→		method: "POST",
 27→		headers: { "Content-Type": "application/json" },
 28→		body: JSON.stringify(params),
 29→	});
 30→	if (!res.ok) {
 31→		var err = await res.json().catch(() => ({ error: "request failed" }));
 32→		throw new Error(err.error || err.code || "browser action failed");
 33→	}
 34→	return res.json();
 35→}
 36→
 37→async function fetchSessions() {
 38→	loading.value = true;
 39→	try {
 40→		var res = await fetch("/api/browser/sessions");
 41→		if (res.ok) {
 42→			var data = await res.json();
 43→			sessions.value = data.sessions || [];
 44→		}
 45→	} catch (e) {
 46→		console.error("Failed to fetch browser sessions:", e);
 47→	} finally {
 48→		loading.value = false;
 49→	}
 50→}
 51→
 52→// ── Screencast frame handling ───────────────────────────────
 53→
 54→var frameUnsub = null;
 55→
 56→function startFrameListener() {
 57→	if (frameUnsub) return;
 58→	frameUnsub = onEvent("browser.screencast.frame", (payload) => {
 59→		if (payload.session_id !== activeSession.value) return;
 60→		frameData.value = payload.data;
 61→		frameMeta.value = payload.metadata;
 62→		frameSeq.value = payload.sequence;
 63→	});
 64→}
 65→
 66→function stopFrameListener() {
 67→	if (frameUnsub) {
 68→		frameUnsub();
 69→		frameUnsub = null;
 70→	}
 71→}
 72→
 73→// ── Session actions ─────────────────────────────────────────
 74→
 75→async function startScreencast(sessionId) {
 76→	try {
 77→		await browserAction({
 78→			session_id: sessionId,
 79→			action: "start_screencast",
 80→			quality: 60,
 81→			max_width: 1280,
 82→			max_height: 800,
 83→		});
 84→		activeSession.value = sessionId;
 85→		screencasting.value = true;
 86→		startFrameListener();
 87→		showToast("Screencast started");
 88→	} catch (e) {
 89→		showToast(`Failed to start screencast: ${e.message}`, "error");
 90→	}
 91→}
 92→
 93→async function stopScreencast(sessionId) {
 94→	try {
 95→		await browserAction({
 96→			session_id: sessionId,
 97→			action: "stop_screencast",
 98→		});
 99→	} catch {
100→		// best effort
101→	}
102→	screencasting.value = false;
103→	activeSession.value = null;
104→	frameData.value = null;
105→	stopFrameListener();
106→	showToast("Screencast stopped");
107→}
108→
109→async function closeSession(sessionId) {
110→	try {
111→		await browserAction({
112→			session_id: sessionId,
113→			action: "close",
114→		});
115→		showToast("Session closed");
116→		if (activeSession.value === sessionId) {
117→			screencasting.value = false;
118→			activeSession.value = null;
119→			frameData.value = null;
120→			stopFrameListener();
121→		}
122→		await fetchSessions();
123→	} catch (e) {
124→		showToast(`Failed to close session: ${e.message}`, "error");
125→	}
126→}
127→
128→async function exportCookies(sessionId) {
129→	try {
130→		var res = await browserAction({
131→			session_id: sessionId,
132→			action: "export_cookies",
133→		});
134→		if (res.cookies && res.cookies.length > 0) {
