266→					<div class="flex items-center gap-1.5 text-xs">
267→						<span class="text-[var(--muted)]">Age: ${formatDuration(sess.age_secs)}</span>
268→						<span class="text-[var(--muted)]">Idle: ${formatDuration(sess.idle_secs)}</span>
269→					</div>
270→					<div class="flex items-center gap-1.5 flex-wrap">
271→						${
272→							activeSession.value === sess.session_id && screencasting.value
273→								? html`<button class="provider-btn-danger text-xs px-2 py-1" onClick=${() => stopScreencast(sess.session_id)}>
274→										Stop Viewing
275→									</button>`
276→								: html`<button class="provider-btn text-xs px-2 py-1" onClick=${() => startScreencast(sess.session_id)}>
277→										View
278→									</button>`
279→						}
280→						<button
281→							class="provider-btn-secondary text-xs px-2 py-1"
282→							onClick=${() => exportCookies(sess.session_id)}
283→						>
284→							Export Cookies
285→						</button>
286→						<button
287→							class="provider-btn-danger text-xs px-2 py-1"
288→							onClick=${() => closeSession(sess.session_id)}
289→						>
290→							Close
291→						</button>
292→					</div>
293→				</div>
294→			`,
295→		)}
296→	</div>`;
297→}
