305→function NavigateBar() {
306→	var [url, setUrl] = useState("");
307→	var [navigating, setNavigating] = useState(false);
308→
309→	async function handleNavigate(e) {
310→		e.preventDefault();
311→		if (!(url.trim() && activeSession.value)) return;
312→		setNavigating(true);
313→		await navigateSession(activeSession.value, url.trim());
314→		setNavigating(false);
315→	}
316→
317→	if (!activeSession.value) return null;
318→
319→	return html`<form onSubmit=${handleNavigate} class="flex items-center gap-2 mb-3">
320→		<input
321→			type="text"
322→			class="flex-1 px-3 py-1.5 text-xs rounded border border-[var(--border)] bg-[var(--surface)] text-[var(--text-strong)] outline-none focus:border-[var(--accent)]"
323→			placeholder="Navigate to URL..."
324→			value=${url}
325→			onInput=${(e) => setUrl(e.target.value)}
326→		/>
327→		<button
328→			type="submit"
329→			class="provider-btn text-xs px-3 py-1.5"
330→			disabled=${navigating || !url.trim()}
331→		>
332→			${navigating ? "..." : "Go"}
333→		</button>
334→	</form>`;
335→}
