337→function BrowserCanvas() {
338→	var canvasRef = useRef(null);
339→	var imgRef = useRef(null);
340→
341→	// Draw frame onto canvas when new frame arrives
342→	useEffect(() => {
343→		if (!(frameData.value && canvasRef.current)) return;
344→		var img = imgRef.current;
345→		if (!img) {
346→			img = new Image();
347→			imgRef.current = img;
348→		}
349→		img.onload = () => {
350→			var canvas = canvasRef.current;
351→			if (!canvas) return;
352→			canvas.width = img.naturalWidth;
353→			canvas.height = img.naturalHeight;
354→			var ctx = canvas.getContext("2d");
355→			ctx.drawImage(img, 0, 0);
356→		};
357→		img.src = `data:image/jpeg;base64,${frameData.value}`;
358→	}, [frameData.value]);
359→
360→	// Attach input handlers
361→	useEffect(() => {
362→		var canvas = canvasRef.current;
363→		if (!canvas) return;
364→
365→		function onMouse(e) {
366→			relayMouseEvent(e, canvas);
367→		}
368→		canvas.addEventListener("mousedown", onMouse);
369→		canvas.addEventListener("mouseup", onMouse);
370→		canvas.addEventListener("mousemove", onMouse);
371→
372→		// Keyboard: focus the canvas to receive key events
373→		canvas.setAttribute("tabindex", "0");
374→		canvas.addEventListener("keydown", relayKeyEvent);
375→		canvas.addEventListener("keyup", relayKeyEvent);
376→
377→		return () => {
378→			canvas.removeEventListener("mousedown", onMouse);
379→			canvas.removeEventListener("mouseup", onMouse);
380→			canvas.removeEventListener("mousemove", onMouse);
381→			canvas.removeEventListener("keydown", relayKeyEvent);
382→			canvas.removeEventListener("keyup", relayKeyEvent);
383→		};
384→	}, []);
385→
386→	if (!(screencasting.value && activeSession.value)) {
387→		return html`<div class="flex-1 flex items-center justify-center text-xs text-[var(--muted)] border border-dashed border-[var(--border)] rounded-lg min-h-[300px]">
388→			Select a session and click "View" to see the browser
389→		</div>`;
390→	}
391→
392→	if (!frameData.value) {
393→		return html`<div class="flex-1 flex items-center justify-center text-xs text-[var(--muted)] border border-dashed border-[var(--border)] rounded-lg min-h-[300px]">
394→			Waiting for first frame...
395→		</div>`;
396→	}
397→
398→	return html`<div class="flex-1 flex flex-col min-h-0">
399→		<div class="flex items-center justify-between mb-1 text-[10px] text-[var(--muted)]">
400→			<span>Session: ${activeSession.value?.slice(0, 12)}...</span>
401→			<span>Frame #${frameSeq.value}</span>
402→			${frameMeta.value ? html`<span>${frameMeta.value.device_width}x${frameMeta.value.device_height}</span>` : null}
403→		</div>
404→		<canvas
405→			ref=${canvasRef}
406→			class="w-full rounded-lg border border-[var(--border)] cursor-crosshair bg-black"
407→			style="aspect-ratio: 16/10; object-fit: contain;"
408→			onClick=${(e) => e.target.focus()}
409→		/>
410→	</div>`;
411→}
