374→        use crate::container;
375→
376→        // All container operations (CLI checks, image pulls, container start +
377→        // readiness polling) use synchronous `std::process::Command` and
378→        // `std::thread::sleep`.  Run them on the blocking thread-pool so they
379→        // don't stall the tokio event loop.
380→        let image = self.config.sandbox_image.clone();
381→        let prefix = self.config.container_prefix.clone();
382→        let vw = self.config.viewport_width;
383→        let vh = self.config.viewport_height;
384→        let low_mem = self.config.low_memory_threshold_mb;
385→        let session_timeout_ms = browserless_session_timeout_ms(
386→            self.config.idle_timeout_secs,
387→            self.config.navigation_timeout_ms,
388→            MAX_BROWSER_INSTANCE_LIFETIME.as_secs(),
389→        );
390→        let profile_dir = sandbox_profile_dir(self.config.resolved_profile_dir(), session_id);
391→        let container_host = self.config.container_host.clone();
392→
393→        let container = tokio::task::spawn_blocking(move || {
394→            // Check container runtime availability (Docker or Apple Container)
395→            if !container::is_container_available() {
396→                return Err(Error::LaunchFailed(
397→                    "No container runtime available for sandboxed browser. \
398→                     Please install Docker or Apple Container."
399→                        .to_string(),
400→                ));
401→            }
402→
403→            // Ensure the container image is available
404→            let t_image = Instant::now();
405→            container::ensure_image(&image)
406→                .map_err(|e| Error::LaunchFailed(format!("failed to ensure browser image: {e}")))?;
407→            info!(
408→                elapsed_ms = t_image.elapsed().as_millis() as u64,
409→                "browser container image ready"
410→            );
411→
412→            // Create profile directory on host if needed.
413→            // The directory must be world-writable (0o777) because the browserless/chrome
414→            // container runs Chrome as uid 999 (`chrome` user), which differs from the
415→            // host uid that owns this directory. Without open permissions the bind-mounted
416→            // volume is not writable and Chrome crashes on startup.

