  1→//! API routes for configuration editing.
  2→//!
  3→//! Provides endpoints to get, validate, and save the full moltis config as TOML.
  4→//!
  5→//! SECURITY: These endpoints expose sensitive configuration including API keys.
  6→//! They are protected by auth middleware, but also have explicit checks to ensure
  7→//! they never work without authentication on non-localhost connections.
  8→
  9→use axum::{Json, extract::State, http::StatusCode, response::IntoResponse};
 10→
 11→const CONFIG_AUTH_REQUIRED: &str = "CONFIG_AUTH_REQUIRED";
 12→const CONFIG_READ_FAILED: &str = "CONFIG_READ_FAILED";
 13→const CONFIG_TOML_REQUIRED: &str = "CONFIG_TOML_REQUIRED";
 14→const CONFIG_INVALID_TOML: &str = "CONFIG_INVALID_TOML";
 15→const CONFIG_SAVE_FAILED: &str = "CONFIG_SAVE_FAILED";
 16→const CONFIG_RESTART_INVALID: &str = "CONFIG_RESTART_INVALID";
 17→const CONFIG_RESTART_READ_FAILED: &str = "CONFIG_RESTART_READ_FAILED";
 18→
 19→fn config_error(code: &str, error: impl Into<String>) -> serde_json::Value {
 20→    serde_json::json!({
 21→        "code": code,
 22→        "error": error.into(),
 23→    })
 24→}
