 85→/// Get the current configuration as TOML.
 86→pub async fn config_get(State(state): State<crate::server::AppState>) -> impl IntoResponse {
 87→    // Extra security check for config access
 88→    if let Err(resp) = require_config_access(&state).await {
 89→        return resp.into_response();
 90→    }
 91→
 92→    // Read raw file from disk to preserve comments.
 93→    // Fall back to the documented template if no config file exists yet.
 94→    let path = moltis_config::find_or_default_config_path();
 95→    let toml_str = if path.exists() {
 96→        match std::fs::read_to_string(&path) {
 97→            Ok(s) => s,
 98→            Err(e) => {
 99→                return (
100→                    StatusCode::INTERNAL_SERVER_ERROR,
101→                    Json(config_error(
102→                        CONFIG_READ_FAILED,
103→                        format!("failed to read config: {e}"),
104→                    )),
105→                )
106→                    .into_response();
107→            },
108→        }
109→    } else {
110→        let config = moltis_config::discover_and_load();
111→        moltis_config::template::default_config_template(config.server.port)
112→    };
113→
114→    Json(serde_json::json!({
115→        "toml": toml_str,
116→        "valid": true,
117→        "path": path.to_string_lossy(),
118→    }))
119→    .into_response()
120→}
