122→/// Validate configuration TOML without saving.
123→pub async fn config_validate(
124→    State(state): State<crate::server::AppState>,
125→    Json(body): Json<serde_json::Value>,
126→) -> impl IntoResponse {
127→    // Extra security check for config access
128→    if let Err(resp) = require_config_access(&state).await {
129→        return resp.into_response();
130→    }
131→
132→    let Some(toml_str) = body.get("toml").and_then(|v| v.as_str()) else {
133→        return (
134→            StatusCode::BAD_REQUEST,
135→            Json(config_error(CONFIG_TOML_REQUIRED, "missing 'toml' field")),
136→        )
137→            .into_response();
138→    };
139→
140→    // Try to parse the TOML as MoltisConfig
141→    match toml::from_str::<moltis_config::MoltisConfig>(toml_str) {
142→        Ok(config) => {
143→            // Run validation checks
144→            let warnings = validate_config(&config);
145→
146→            Json(serde_json::json!({
147→                "valid": true,
148→                "warnings": warnings,
149→            }))
150→            .into_response()
151→        },
152→        Err(e) => {
153→            // Parse error message to extract line/column if available
154→            let error_msg = e.to_string();
155→            Json(serde_json::json!({
156→                "code": CONFIG_INVALID_TOML,
157→                "valid": false,
158→                "error": error_msg,
159→            }))
160→            .into_response()
161→        },
162→    }
163→}
