165→/// Get the default configuration template with all options documented.
166→/// Preserves the current port from the existing config.
167→pub async fn config_template(State(state): State<crate::server::AppState>) -> impl IntoResponse {
168→    // Extra security check for config access
169→    if let Err(resp) = require_config_access(&state).await {
