183→/// Save configuration from TOML.
184→pub async fn config_save(
185→    State(state): State<crate::server::AppState>,
186→    Json(body): Json<serde_json::Value>,
187→) -> impl IntoResponse {
188→    // Extra security check for config access
189→    if let Err(resp) = require_config_access(&state).await {
190→        return resp.into_response();
191→    }
192→
193→    let Some(toml_str) = body.get("toml").and_then(|v| v.as_str()) else {
194→        return (
195→            StatusCode::BAD_REQUEST,
196→            Json(config_error(CONFIG_TOML_REQUIRED, "missing 'toml' field")),
197→        )
198→            .into_response();
199→    };
200→
201→    // Validate by parsing, then write raw string to preserve comments.
202→    if let Err(e) = toml::from_str::<moltis_config::MoltisConfig>(toml_str) {
203→        return (
204→            StatusCode::BAD_REQUEST,
205→            Json(serde_json::json!({
206→                "code": CONFIG_INVALID_TOML,
207→                "error": format!("invalid TOML: {e}"),
208→                "valid": false,
209→            })),
210→        )
211→            .into_response();
212→    }
213→
214→    match moltis_config::save_raw_config(toml_str) {
215→        Ok(path) => {
216→            tracing::info!(path = %path.display(), "saved config (raw)");
217→            Json(serde_json::json!({
218→                "ok": true,
219→                "path": path.to_string_lossy(),
220→                "restart_required": true,
221→            }))
222→            .into_response()
223→        },
224→        Err(e) => (
225→            StatusCode::INTERNAL_SERVER_ERROR,
226→            Json(config_error(
227→                CONFIG_SAVE_FAILED,
228→                format!("failed to save config: {e}"),
229→            )),
230→        )
231→            .into_response(),
232→    }
233→}
