235→/// Restart the moltis process.
236→///
237→/// This re-runs the current binary with the same arguments. On Unix, it uses the exec
238→/// syscall to replace the current process. On other platforms, it spawns a new process.
239→///
240→/// Before restarting, the saved config is loaded from disk and validated. If the config
241→/// is invalid the restart is refused so the server doesn't crash on startup.
242→pub async fn restart(State(state): State<crate::server::AppState>) -> impl IntoResponse {
243→    // Extra security check for config access (restart is a privileged operation)
244→    if let Err(resp) = require_config_access(&state).await {
245→        return resp.into_response();
246→    }
247→
248→    // Validate the on-disk config before restarting to avoid crash loops.
249→    let config_path = moltis_config::find_or_default_config_path();
250→    if config_path.exists() {
251→        match std::fs::read_to_string(&config_path) {
252→            Ok(toml_str) => {
253→                if let Err(e) = toml::from_str::<moltis_config::MoltisConfig>(&toml_str) {
254→                    tracing::warn!(
255→                        path = %config_path.display(),
256→                        error = %e,
257→                        "restart refused: saved config is invalid"
258→                    );
259→                    return (
260→                        StatusCode::BAD_REQUEST,
261→                        Json(serde_json::json!({
262→                            "code": CONFIG_RESTART_INVALID,
263→                            "error": format!("Config is invalid, refusing to restart: {e}"),
264→                            "valid": false,
265→                        })),
266→                    )
267→                        .into_response();
268→                }
269→            },
270→            Err(e) => {
271→                tracing::warn!(
272→                    path = %config_path.display(),
273→                    error = %e,
274→                    "restart refused: cannot read config file"
275→                );
276→                return (
277→                    StatusCode::INTERNAL_SERVER_ERROR,
278→                    Json(config_error(
279→                        CONFIG_RESTART_READ_FAILED,
280→                        format!("Cannot read config file: {e}"),
281→                    )),
282→                )
283→                    .into_response();
284→            },
285→        }
286→    }
287→
288→    tracing::info!("restart requested via API");
289→
290→    // Spawn a task to restart after a short delay, allowing the response to be sent first.
291→    tokio::spawn(async {
292→        tokio::time::sleep(std::time::Duration::from_millis(300)).await;
293→        tracing::info!("restarting now");
294→
295→        let exe = match std::env::current_exe() {
296→            Ok(path) => path,
297→            Err(e) => {
298→                tracing::error!("failed to get current executable path: {e}");
299→                std::process::exit(1);
300→            },
301→        };
302→
303→        let args: Vec<String> = std::env::args().skip(1).collect();
304→        tracing::info!(exe = %exe.display(), args = ?args, "re-executing");
305→
306→        // Use exec on Unix to replace the current process in-place
307→        #[cfg(unix)]
308→        {
309→            use std::os::unix::process::CommandExt;
310→            // This replaces the current process and never returns on success
311→            let err = std::process::Command::new(&exe).args(&args).exec();
312→            tracing::error!("failed to exec: {err}");
313→            std::process::exit(1);
314→        }
315→
316→        // On non-Unix, spawn a new process and exit the current one
317→        #[cfg(not(unix))]
318→        {
319→            match std::process::Command::new(&exe).args(&args).spawn() {
320→                Ok(_) => {
321→                    tracing::info!("spawned new process, exiting current");
322→                    std::process::exit(0);
323→                },
324→                Err(e) => {
325→                    tracing::error!("failed to spawn new process: {e}");
326→                    std::process::exit(1);
327→                },
328→            }
329→        }
330→    });
331→
332→    Json(serde_json::json!({
333→        "ok": true,
334→        "message": "Moltis is restarting..."
335→    }))
336→    .into_response()
337→}
