339→/// Validate config and return warnings.
340→fn validate_config(config: &moltis_config::MoltisConfig) -> Vec<String> {
341→    let mut warnings = Vec::new();
342→
343→    // Check browser config
344→    if config.tools.browser.enabled {
345→        // Browser sandbox mode follows session sandbox mode (controlled by exec.sandbox.mode).
346→        // If sandbox mode is available, check if container runtime exists.
347→        if config.tools.exec.sandbox.mode != "off"
348→            && !moltis_browser::container::is_container_available()
349→        {
350→            warnings.push(
351→                "Sandbox mode is available but no container runtime found. \
352→                 Browser sandbox (for sandboxed sessions) requires Docker or Apple Container."
353→                    .to_string(),
354→            );
355→        }
356→
357→        if config.tools.browser.allowed_domains.is_empty() {
358→            warnings.push(
359→                "No allowed_domains set for browser. All domains are accessible. \
360→                 Consider restricting to trusted domains for security."
361→                    .to_string(),
362→            );
363→        }
364→
365→        if config.tools.browser.max_instances > 10 {
366→            warnings.push(format!(
367→                "max_instances={} is high. Consider reducing to prevent resource exhaustion.",
368→                config.tools.browser.max_instances
369→            ));
370→        }
371→    }
372→
373→    // Check exec config
374→    if config.tools.exec.sandbox.mode == "off" {
375→        warnings.push(
376→            "Sandbox mode is off. Commands will run directly on host without isolation."
377→                .to_string(),
378→        );
379→    }
380→
381→    // Check auth config
382→    if config.auth.disabled {
383→        warnings.push(
384→            "Authentication is disabled. Anyone with network access can use the gateway."
385→                .to_string(),
386→        );
387→    }
388→
389→    // Check TLS config
390→    if !config.tls.enabled {
391→        warnings.push("TLS is disabled. Connections will use unencrypted HTTP.".to_string());
392→    }
393→
394→    // Check heartbeat active hours
395→    if config.heartbeat.enabled
396→        && config.heartbeat.active_hours.start == config.heartbeat.active_hours.end
397→    {
398→        warnings.push(
399→            "Heartbeat active_hours start and end are the same. Heartbeat may not run.".to_string(),
400→        );
401→    }
402→
403→    warnings
404→}
