            model_path: Some(PathBuf::from("/tmp/custom-qwen.gguf")),
            hf_repo: Some("Qwen/Qwen3-4B-GGUF".into()),
            hf_filename: Some("Qwen3-4B-Q4_K_M.gguf".into()),
            gpu_layers: 0,
            backend: "GGUF".into(),
