  1→//! CDP screencast: stream browser page frames via `Page.startScreencast`.
  2→//!
  3→//! Each active screencast gets a background task that listens for
  4→//! `Page.screencastFrame` CDP events, acknowledges them, and forwards
  5→//! the base64 JPEG frame data to a broadcast channel that the gateway
  6→//! can relay to WebSocket clients.
  7→
  8→use std::{collections::HashMap, sync::Arc};
  9→
 10→use {
 11→    chromiumoxide::{
 12→        Page,
 13→        cdp::browser_protocol::page::{
 14→            EventScreencastFrame, ScreencastFrameAckParams, StartScreencastFormat,
 15→            StartScreencastParams, StopScreencastParams,
 16→        },
 17→    },
 18→    futures::StreamExt,
 19→    serde::Serialize,
 20→    tokio::sync::{RwLock, broadcast},
 21→    tracing::{debug, warn},
 22→};
 23→
 24→/// A single screencast frame delivered to subscribers.
 25→#[derive(Debug, Clone, Serialize)]
 26→pub struct ScreencastFrame {
 27→    /// Browser session ID this frame belongs to.
 28→    pub session_id: String,
 29→    /// Base64-encoded JPEG image data.
 30→    pub data: String,
 31→    /// Frame metadata.
 32→    pub metadata: FrameMetadata,
 33→    /// Monotonically increasing frame sequence number.
 34→    pub sequence: u64,
 35→}
 36→
 37→/// Metadata for a screencast frame.
 38→#[derive(Debug, Clone, Serialize)]
 39→pub struct FrameMetadata {
 40→    pub offset_top: f64,
 41→    pub page_scale_factor: f64,
 42→    pub device_width: f64,
 43→    pub device_height: f64,
 44→    pub scroll_offset_x: f64,
 45→    pub scroll_offset_y: f64,
 46→    pub timestamp: f64,
 47→}
 48→
 49→/// Channel capacity for screencast frame broadcasts.
 50→const FRAME_CHANNEL_CAPACITY: usize = 4;
 51→
 52→/// Handle to a running screencast. Cloneable for multi-subscriber use.
 53→pub struct ScreencastHandle {
 54→    tx: broadcast::Sender<ScreencastFrame>,
 55→    session_id: String,
 56→}
 57→
 58→impl ScreencastHandle {
 59→    /// Subscribe a new receiver to this screencast's frame stream.
 60→    pub fn subscribe(&self) -> broadcast::Receiver<ScreencastFrame> {
 61→        self.tx.subscribe()
 62→    }
 63→
 64→    /// The browser session ID this screencast belongs to.
 65→    pub fn session_id(&self) -> &str {
 66→        &self.session_id
 67→    }
 68→}
 69→
 70→/// Registry of active screencasts, keyed by browser session ID.
 71→#[derive(Default)]
 72→pub struct ScreencastRegistry {
 73→    active: RwLock<HashMap<String, Arc<ActiveScreencast>>>,
 74→}
 75→
 76→struct ActiveScreencast {
 77→    tx: broadcast::Sender<ScreencastFrame>,
 78→    abort: tokio::task::AbortHandle,
 79→}
 80→
 81→impl Drop for ActiveScreencast {
 82→    fn drop(&mut self) {
 83→        self.abort.abort();
 84→    }
 85→}
 86→
 87→impl ScreencastRegistry {
 88→    pub fn new() -> Self {
 89→        Self::default()
 90→    }
 91→
 92→    /// Start a screencast for the given page and session ID.
 93→    ///
 94→    /// Returns a [`broadcast::Receiver`] for frame events. If a screencast is
 95→    /// already active for this session, returns a new subscriber to the
 96→    /// existing stream.
 97→    pub async fn start(
 98→        &self,
 99→        session_id: &str,
100→        page: &Page,
101→        quality: u8,
102→        max_width: u32,
103→        max_height: u32,
104→    ) -> Result<broadcast::Receiver<ScreencastFrame>, crate::error::Error> {
105→        // If already active, return a new subscriber.
106→        {
107→            let active = self.active.read().await;
108→            if let Some(handle) = active.get(session_id) {
109→                debug!(session_id, "screencast already active, adding subscriber");
110→                return Ok(handle.tx.subscribe());
111→            }
112→        }
113→
114→        // Start CDP screencast via the builder pattern.
115→        let params = StartScreencastParams {
116→            format: Some(StartScreencastFormat::Jpeg),
117→            quality: Some(i64::from(quality.min(100))),
118→            max_width: Some(i64::from(max_width)),
119→            max_height: Some(i64::from(max_height)),
120→            every_nth_frame: Some(1),
121→        };
122→
123→        page.execute(params)
124→            .await
125→            .map_err(|e| crate::error::Error::Cdp(format!("failed to start screencast: {e}")))?;
126→
127→        let (tx, rx) = broadcast::channel(FRAME_CHANNEL_CAPACITY);
128→
129→        // Spawn background task to relay CDP screencast frame events.
130→        let tx_clone = tx.clone();
131→        let sid = session_id.to_string();
132→        let page_clone = page.clone();
133→
134→        let task = tokio::spawn(async move {
135→            relay_screencast_frames(page_clone, tx_clone, sid).await;
136→        });
137→
138→        let inner = Arc::new(ActiveScreencast {
139→            tx: tx.clone(),
140→            abort: task.abort_handle(),
141→        });
142→
143→        self.active
144→            .write()
145→            .await
146→            .insert(session_id.to_string(), inner);
147→
148→        debug!(session_id, "screencast started");
149→        Ok(rx)
150→    }
151→
152→    /// Stop the screencast for the given session.
153→    pub async fn stop(
154→        &self,
155→        session_id: &str,
156→        page: Option<&Page>,
157→    ) -> Result<(), crate::error::Error> {
158→        let removed = self.active.write().await.remove(session_id);
159→        if removed.is_some() {
160→            // Try to send stop command to CDP (best effort).
161→            if let Some(page) = page {
162→                let _ = page.execute(StopScreencastParams::default()).await;
163→            }
164→            debug!(session_id, "screencast stopped");
165→        }
166→        Ok(())
167→    }
168→
169→    /// Subscribe to an existing screencast for the given session.
170→    pub async fn subscribe(
171→        &self,
172→        session_id: &str,
173→    ) -> Option<broadcast::Receiver<ScreencastFrame>> {
174→        let active = self.active.read().await;
175→        active.get(session_id).map(|h| h.tx.subscribe())
176→    }
177→
178→    /// Check if a screencast is active for the given session.
179→    pub async fn is_active(&self, session_id: &str) -> bool {
180→        self.active.read().await.contains_key(session_id)
181→    }
182→
183→    /// List all active screencast session IDs.
184→    pub async fn active_sessions(&self) -> Vec<String> {
185→        self.active.read().await.keys().cloned().collect()
186→    }
187→
188→    /// Stop all screencasts. Called during shutdown.
189→    pub async fn stop_all(&self) {
190→        let mut active = self.active.write().await;
191→        active.clear(); // Arc<Inner> drop aborts tasks
192→    }
193→}
194→
195→/// Background task: listen for CDP screencast frame events and forward them.
196→async fn relay_screencast_frames(
197→    page: Page,
198→    tx: broadcast::Sender<ScreencastFrame>,
199→    session_id: String,
200→) {
201→    let mut listener = match page.event_listener::<EventScreencastFrame>().await {
202→        Ok(l) => l,
203→        Err(e) => {
204→            warn!(session_id = %session_id, error = %e, "failed to subscribe to screencast frames");
205→            return;
206→        },
207→    };
208→
209→    let mut sequence: u64 = 0;
210→
211→    while let Some(event) = listener.next().await {
212→        sequence += 1;
213→
214→        // Acknowledge the frame so CDP sends the next one.
215→        let ack = ScreencastFrameAckParams::new(event.session_id);
216→        if let Err(e) = page.execute(ack).await {
217→            warn!(session_id = %session_id, error = %e, "failed to ack screencast frame");
218→        }
219→
220→        let meta = &event.metadata;
221→        let frame = ScreencastFrame {
222→            session_id: session_id.clone(),
223→            data: event.data.clone().into(),
224→            metadata: FrameMetadata {
225→                offset_top: meta.offset_top,
226→                page_scale_factor: meta.page_scale_factor,
227→                device_width: meta.device_width,
228→                device_height: meta.device_height,
229→                scroll_offset_x: meta.scroll_offset_x,
230→                scroll_offset_y: meta.scroll_offset_y,
231→                timestamp: meta.timestamp.as_ref().map(|t| *t.inner()).unwrap_or(0.0),
232→            },
233→            sequence,
234→        };
235→
236→        // Send to all subscribers (ignore lagged receivers).
237→        if tx.send(frame).is_err() {
238→            debug!(session_id = %session_id, "no screencast subscribers, stopping relay");
239→            break;
240→        }
241→    }
242→
243→    debug!(session_id = %session_id, "screencast frame relay ended");
244→}
245→
246→#[cfg(test)]
247→mod tests {
248→    use super::*;
249→
250→    #[test]
251→    fn frame_metadata_serializes() {
252→        let frame = ScreencastFrame {
253→            session_id: "test".into(),
254→            data: "AAAA".into(),
255→            metadata: FrameMetadata {
256→                offset_top: 0.0,
257→                page_scale_factor: 1.0,
258→                device_width: 1280.0,
259→                device_height: 800.0,
260→                scroll_offset_x: 0.0,
261→                scroll_offset_y: 0.0,
262→                timestamp: 123.456,
263→            },
264→            sequence: 1,
265→        };
266→        let json = serde_json::to_string(&frame);
267→        assert!(json.is_ok());
268→    }
269→
270→    #[test]
271→    fn registry_is_default() {
272→        let _reg = ScreencastRegistry::new();
273→    }
274→}
