  1→//! Browser instance pool management.
  2→
  3→use std::{
  4→    collections::HashMap,
  5→    path::PathBuf,
  6→    sync::Arc,
  7→    time::{Duration, Instant},
  8→};
  9→
 10→use {
 11→    chromiumoxide::{
 12→        Browser, BrowserConfig as CdpBrowserConfig, Page,
 13→        cdp::browser_protocol::emulation::SetDeviceMetricsOverrideParams, handler::HandlerConfig,
 14→    },
 15→    futures::StreamExt,
 16→    sysinfo::System,
 17→    tokio::sync::{Mutex, RwLock},
 18→    tracing::{debug, info, warn},
 19→};
 20→
 21→use crate::{
 22→    container::{BrowserContainer, browserless_session_timeout_ms},
 23→    error::Error,
 24→    types::{BrowserConfig, BrowserPreference},
 25→};
 26→
 27→pub(crate) const MAX_BROWSER_INSTANCE_LIFETIME: Duration = Duration::from_secs(30 * 60);
 28→
 29→/// Information about an active browser session.
 30→#[derive(Debug, Clone, serde::Serialize)]
 31→pub struct BrowserSessionInfo {
 32→    pub session_id: String,
 33→    pub sandboxed: bool,
 34→    pub url: String,
 35→    pub age_secs: u64,
 36→    pub idle_secs: u64,
 37→}
 38→
 39→/// Get current system memory usage as a percentage (0-100).
 40→fn get_memory_usage_percent() -> u8 {
 41→    let mut sys = System::new();
 42→    sys.refresh_memory();
 43→
 44→    let total = sys.total_memory();
 45→    if total == 0 {
 46→        return 0;
 47→    }
 48→
 49→    let used = sys.used_memory();
 50→    let percent = (used as f64 / total as f64 * 100.0) as u8;
 51→    percent.min(100)
 52→}
 53→
 54→/// Returns memory-saving Chrome flags when `total_mb` is below `threshold_mb`.
 55→///
 56→/// Returns an empty slice when the threshold is 0 (disabled) or when the system
 57→/// has enough memory.
 58→#[must_use]
 59→pub(crate) fn low_memory_chrome_args(total_mb: u64, threshold_mb: u64) -> &'static [&'static str] {
 60→    if threshold_mb == 0 || total_mb >= threshold_mb {
 61→        return &[];
 62→    }
 63→    &[
 64→        "--single-process",
 65→        "--renderer-process-limit=1",
 66→        "--js-flags=--max-old-space-size=128",
 67→    ]
 68→}
 69→
 70→/// A pooled browser instance with one or more pages.
 71→struct BrowserInstance {
 72→    browser: Browser,
 73→    pages: HashMap<String, Page>,
 74→    last_used: Instant,
 75→    /// When this instance was first created. Used to enforce a hard TTL that
 76→    /// prevents Chromium memory leaks from accumulating in long-lived instances.
 77→    created_at: Instant,
 78→    /// Whether this instance is running in sandbox mode.
 79→    #[allow(dead_code)]
 80→    sandboxed: bool,
 81→    /// Container for sandboxed instances (None for host browser).
 82→    #[allow(dead_code)]
 83→    container: Option<BrowserContainer>,
 84→}
 85→
 86→/// Pool of browser instances for reuse.
 87→pub struct BrowserPool {
 88→    config: BrowserConfig,
 89→    instances: RwLock<HashMap<String, Arc<Mutex<BrowserInstance>>>>,
 90→    #[cfg(feature = "metrics")]
 91→    active_count: std::sync::atomic::AtomicUsize,
 92→}
 93→
 94→impl BrowserPool {
 95→    /// Create a new browser pool with the given configuration.
 96→    pub fn new(config: BrowserConfig) -> Self {
 97→        Self {
 98→            config,
 99→            instances: RwLock::new(HashMap::new()),
100→            #[cfg(feature = "metrics")]
101→            active_count: std::sync::atomic::AtomicUsize::new(0),
102→        }
103→    }
104→
105→    /// Get or create a browser instance for the given session ID.
106→    /// Returns the session ID for the browser instance.
107→    ///
108→    /// The `sandbox` parameter determines whether to run the browser in a
109→    /// Docker container (true) or on the host (false). This is set when
110→    /// creating a new session and cannot be changed for existing sessions.
111→    pub async fn get_or_create(
112→        &self,
113→        session_id: Option<&str>,
114→        sandbox: bool,
115→        browser: Option<BrowserPreference>,
116→    ) -> Result<String, Error> {
117→        // Treat empty string as None (generate new session ID)
118→        let session_id = session_id.filter(|s| !s.is_empty());
119→
120→        // Check if we have an existing instance
121→        if let Some(sid) = session_id {
122→            let instances = self.instances.read().await;
123→            if instances.contains_key(sid) {
124→                debug!(session_id = sid, "reusing existing browser instance");
125→                return Ok(sid.to_string());
126→            }
127→        }
128→
129→        // Check pool capacity using memory-based limits
130→        {
131→            // If max_instances is set (> 0), enforce it as a hard limit
132→            if self.config.max_instances > 0 {
133→                let instances = self.instances.read().await;
134→                if instances.len() >= self.config.max_instances {
135→                    drop(instances);
136→                    self.cleanup_idle().await;
137→
138→                    let instances = self.instances.read().await;
139→                    if instances.len() >= self.config.max_instances {
140→                        return Err(Error::PoolExhausted);
141→                    }
142→                }
143→            }
144→
145→            // Check memory usage - block new instances if above threshold
146→            let memory_percent = get_memory_usage_percent();
147→            if memory_percent >= self.config.memory_limit_percent {
148→                // Try to clean up idle instances first
149→                self.cleanup_idle().await;
150→
151→                // Re-check memory after cleanup
152→                let memory_after = get_memory_usage_percent();
153→                if memory_after >= self.config.memory_limit_percent {
154→                    warn!(
155→                        memory_usage = memory_after,
156→                        threshold = self.config.memory_limit_percent,
157→                        "blocking new browser instance due to high memory usage"
158→                    );
159→                    return Err(Error::PoolExhausted);
160→                }
161→            }
162→        }
163→
164→        // Create new instance
165→        let sid = session_id
166→            .map(String::from)
167→            .unwrap_or_else(generate_session_id);
168→
169→        let instance = self.launch_browser(&sid, sandbox, browser).await?;
170→        let instance = Arc::new(Mutex::new(instance));
171→
172→        {
173→            let mut instances = self.instances.write().await;
174→            instances.insert(sid.clone(), instance);
175→        }
176→
177→        #[cfg(feature = "metrics")]
178→        {
179→            self.active_count
180→                .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
181→            moltis_metrics::gauge!(moltis_metrics::browser::INSTANCES_ACTIVE)
182→                .set(self.active_count.load(std::sync::atomic::Ordering::Relaxed) as f64);
183→            moltis_metrics::counter!(moltis_metrics::browser::INSTANCES_CREATED_TOTAL).increment(1);
184→        }
185→
186→        let mode = if sandbox {
187→            "sandboxed"
188→        } else {
189→            "host"
190→        };
191→        info!(session_id = sid, mode, "launched new browser instance");
192→        Ok(sid)
193→    }
194→
195→    /// Get the page for a session, creating one if needed.
196→    pub async fn get_page(&self, session_id: &str) -> Result<Page, Error> {
197→        let instances = self.instances.read().await;
198→        let instance = instances.get(session_id).ok_or(Error::ElementNotFound(0))?;
199→
200→        let mut inst = instance.lock().await;
201→        inst.last_used = Instant::now();
202→
203→        // Get or create the main page
204→        if let Some(page) = inst.pages.get("main") {
205→            debug!(session_id, "reusing existing page");
206→            return Ok(page.clone());
207→        }
208→
209→        // Create a new page
210→        let page = inst
211→            .browser
212→            .new_page("about:blank")
213→            .await
214→            .map_err(|e| Error::LaunchFailed(e.to_string()))?;
215→
216→        // Explicitly set viewport on page to ensure it matches config
217→        // (browser-level viewport may not always be applied to new pages)
218→        let viewport_cmd = SetDeviceMetricsOverrideParams::builder()
219→            .width(self.config.viewport_width)
220→            .height(self.config.viewport_height)
221→            .device_scale_factor(self.config.device_scale_factor)
222→            .mobile(false)
223→            .build()
224→            .map_err(|e| Error::Cdp(format!("invalid viewport params: {e}")))?;
225→
226→        if let Err(e) = page.execute(viewport_cmd).await {
227→            warn!(session_id, error = %e, "failed to set page viewport");
228→        }
229→
230→        info!(
231→            session_id,
232→            viewport_width = self.config.viewport_width,
233→            viewport_height = self.config.viewport_height,
234→            device_scale_factor = self.config.device_scale_factor,
235→            "created new page with viewport"
236→        );
237→
238→        inst.pages.insert("main".to_string(), page.clone());
239→        Ok(page)
240→    }
241→
242→    /// Close a specific browser session.
243→    pub async fn close_session(&self, session_id: &str) -> Result<(), Error> {
244→        let instance = {
245→            let mut instances = self.instances.write().await;
246→            instances.remove(session_id)
247→        };
248→
249→        if let Some(instance) = instance {
250→            let inst = instance.lock().await;
251→            // Pages are closed when browser is dropped
252→            drop(inst);
253→
254→            #[cfg(feature = "metrics")]
255→            {
256→                self.active_count
257→                    .fetch_sub(1, std::sync::atomic::Ordering::Relaxed);
258→                moltis_metrics::gauge!(moltis_metrics::browser::INSTANCES_ACTIVE)
259→                    .set(self.active_count.load(std::sync::atomic::Ordering::Relaxed) as f64);
260→                moltis_metrics::counter!(moltis_metrics::browser::INSTANCES_DESTROYED_TOTAL)
261→                    .increment(1);
262→            }
263→
264→            info!(session_id, "closed browser session");
265→        }
266→
267→        Ok(())
268→    }
269→
270→    /// Clean up idle browser instances and instances that have exceeded the
271→    /// hard TTL ([`MAX_BROWSER_INSTANCE_LIFETIME`]). The TTL prevents Chromium
272→    /// memory leaks from accumulating in long-lived browser instances.
273→    pub async fn cleanup_idle(&self) {
274→        let idle_timeout = Duration::from_secs(self.config.idle_timeout_secs);
275→        let now = Instant::now();
276→
277→        let mut to_remove = Vec::new();
278→
279→        {
280→            let instances = self.instances.read().await;
281→            for (sid, instance) in instances.iter() {
282→                if let Ok(inst) = instance.try_lock() {
283→                    let idle = now.duration_since(inst.last_used) > idle_timeout;
284→                    let expired =
285→                        now.duration_since(inst.created_at) > MAX_BROWSER_INSTANCE_LIFETIME;
286→                    if idle || expired {
287→                        if expired {
288→                            info!(
289→                                session_id = sid,
290→                                age_secs = inst.created_at.elapsed().as_secs(),
291→                                "browser instance exceeded max lifetime"
292→                            );
293→                        }
294→                        to_remove.push(sid.clone());
295→                    }
296→                }
297→            }
298→        }
299→
300→        if to_remove.is_empty() {
301→            return;
302→        }
303→
304→        info!(
305→            count = to_remove.len(),
306→            sessions = ?to_remove,
307→            "cleaning up browser sessions"
308→        );
309→
310→        for sid in to_remove {
311→            if let Err(e) = self.close_session(&sid).await {
312→                warn!(session_id = sid, error = %e, "failed to close session");
313→            }
314→        }
315→    }
316→
317→    /// Shut down all browser instances.
318→    pub async fn shutdown(&self) {
319→        let sessions: Vec<String> = {
320→            let instances = self.instances.read().await;
321→            instances.keys().cloned().collect()
322→        };
323→
324→        for sid in sessions {
325→            let _ = self.close_session(&sid).await;
326→        }
327→
328→        info!("browser pool shut down");
329→    }
330→
331→    /// Get the number of active instances.
332→    pub async fn active_count(&self) -> usize {
333→        self.instances.read().await.len()
334→    }
