336→    /// List all active session IDs with their metadata.
337→    pub async fn list_sessions(&self) -> Vec<BrowserSessionInfo> {
338→        let instances = self.instances.read().await;
339→        let mut sessions = Vec::with_capacity(instances.len());
340→        for (sid, instance) in instances.iter() {
341→            let inst = instance.lock().await;
342→            let url = if let Some(page) = inst.pages.values().next() {
343→                page.url().await.ok().flatten().unwrap_or_default()
344→            } else {
345→                String::new()
346→            };
347→            sessions.push(BrowserSessionInfo {
348→                session_id: sid.clone(),
349→                sandboxed: inst.sandboxed,
350→                url,
351→                age_secs: inst.created_at.elapsed().as_secs(),
352→                idle_secs: inst.last_used.elapsed().as_secs(),
353→            });
354→        }
355→        sessions
356→    }
