372→    /// Launch a browser inside a container (sandboxed mode).
373→    async fn launch_sandboxed_browser(&self, session_id: &str) -> Result<BrowserInstance, Error> {
374→        use crate::container;
375→
376→        // All container operations (CLI checks, image pulls, container start +
377→        // readiness polling) use synchronous `std::process::Command` and
378→        // `std::thread::sleep`.  Run them on the blocking thread-pool so they
379→        // don't stall the tokio event loop.
380→        let image = self.config.sandbox_image.clone();
381→        let prefix = self.config.container_prefix.clone();
382→        let vw = self.config.viewport_width;
383→        let vh = self.config.viewport_height;
384→        let low_mem = self.config.low_memory_threshold_mb;
385→        let session_timeout_ms = browserless_session_timeout_ms(
386→            self.config.idle_timeout_secs,
387→            self.config.navigation_timeout_ms,
388→            MAX_BROWSER_INSTANCE_LIFETIME.as_secs(),
389→        );
390→        let profile_dir = sandbox_profile_dir(self.config.resolved_profile_dir(), session_id);
391→        let container_host = self.config.container_host.clone();
392→
393→        let container = tokio::task::spawn_blocking(move || {
394→            // Check container runtime availability (Docker or Apple Container)
395→            if !container::is_container_available() {
396→                return Err(Error::LaunchFailed(
397→                    "No container runtime available for sandboxed browser. \
398→                     Please install Docker or Apple Container."
399→                        .to_string(),
400→                ));
401→            }
402→
403→            // Ensure the container image is available
404→            let t_image = Instant::now();
405→            container::ensure_image(&image)
406→                .map_err(|e| Error::LaunchFailed(format!("failed to ensure browser image: {e}")))?;
407→            info!(
408→                elapsed_ms = t_image.elapsed().as_millis() as u64,
409→                "browser container image ready"
410→            );
411→
412→            // Create profile directory on host if needed.
413→            // The directory must be world-writable (0o777) because the browserless/chrome
414→            // container runs Chrome as uid 999 (`chrome` user), which differs from the
415→            // host uid that owns this directory. Without open permissions the bind-mounted
416→            // volume is not writable and Chrome crashes on startup.
417→            // This is safe: the directory is Moltis-managed (~/.moltis/browser/profile/)
418→            // and contains only ephemeral Chrome profile data (cache, cookies, local
419→            // storage). It is not a system directory and has no security-sensitive content.
420→            if let Some(ref dir) = profile_dir {
421→                match std::fs::create_dir_all(dir) {
422→                    Err(e) => warn!(
423→                        path = %dir.display(),
424→                        error = %e,
425→                        "failed to create browser profile directory for container"
426→                    ),
427→                    Ok(()) => set_container_dir_permissions(dir),
428→                }
429→            }
430→
431→            // Start the container (includes readiness polling)
432→            BrowserContainer::start(
433→                &image,
434→                &prefix,
435→                vw,
436→                vh,
437→                low_mem,
438→                session_timeout_ms,
439→                profile_dir.as_deref(),
440→                &container_host,
441→            )
442→            .map_err(|e| Error::LaunchFailed(format!("failed to start browser container: {e}")))
443→        })
444→        .await
445→        .map_err(|e| Error::LaunchFailed(format!("container launch task panicked: {e}")))??;
446→
447→        let ws_url = container.websocket_url();
448→        info!(
449→            session_id,
450→            container_id = container.id(),
451→            ws_url,
452→            "connecting to sandboxed browser"
453→        );
454→
455→        // Connect to the containerized browser with custom timeout
456→        let handler_config = HandlerConfig {
457→            request_timeout: Duration::from_millis(self.config.navigation_timeout_ms),
458→            viewport: Some(chromiumoxide::handler::viewport::Viewport {
459→                width: self.config.viewport_width,
460→                height: self.config.viewport_height,
461→                device_scale_factor: Some(self.config.device_scale_factor),
462→                emulating_mobile: false,
463→                is_landscape: true,
464→                has_touch: false,
465→            }),
466→            ..Default::default()
467→        };
468→
469→        let (browser, mut handler) = Browser::connect_with_config(&ws_url, handler_config)
470→            .await
471→            .map_err(|e| {
472→                Error::LaunchFailed(format!(
473→                    "failed to connect to containerized browser at {}: {}",
474→                    ws_url, e
475→                ))
476→            })?;
477→
478→        // Spawn handler to process browser events
479→        let session_id_clone = session_id.to_string();
480→        tokio::spawn(async move {
481→            while let Some(event) = handler.next().await {
482→                debug!(session_id = session_id_clone, ?event, "browser event");
483→            }
484→            // Handler exits when connection closes - this is normal for idle sessions
485→            debug!(
486→                session_id = session_id_clone,
487→                "sandboxed browser event handler exited (connection closed)"
488→            );
489→        });
490→
491→        info!(session_id, "sandboxed browser connected successfully");
492→
493→        Ok(BrowserInstance {
494→            browser,
495→            pages: HashMap::new(),
496→            last_used: Instant::now(),
497→            created_at: Instant::now(),
498→            sandboxed: true,
499→            container: Some(container),
500→        })
501→    }
502→
503→    /// Launch a browser on the host (non-sandboxed mode).
504→    async fn launch_host_browser(
505→        &self,
506→        session_id: &str,
507→        browser: Option<BrowserPreference>,
508→    ) -> Result<BrowserInstance, Error> {
509→        let requested_browser = browser.unwrap_or_default();
510→
511→        // Detect all installed browser candidates.
512→        let mut detection = crate::detect::detect_browser(self.config.chrome_path.as_deref());
513→        let mut install_attempt: Option<crate::detect::AutoInstallResult> = None;
514→
515→        // Auto-install is always on: if none are installed, try to install one.
516→        if detection.browsers.is_empty() {
517→            let result = crate::detect::auto_install_browser(requested_browser).await;
518→            if result.attempted && result.installed {
519→                info!(details = %result.details, "auto-installed browser on host");
520→            } else if result.attempted {
521→                warn!(details = %result.details, "browser auto-install failed");
522→            } else {
523→                warn!(
524→                    details = %result.details,
525→                    "browser auto-install skipped (installer unavailable)"
526→                );
527→            }
528→            install_attempt = Some(result);
529→            detection = crate::detect::detect_browser(self.config.chrome_path.as_deref());
530→        }
531→
532→        if detection.browsers.is_empty() {
533→            let mut message = format!("No compatible browser found. {}", detection.install_hint);
534→            if let Some(attempt) = install_attempt
535→                && attempt.attempted
536→            {
537→                message.push_str("\n\nAuto-install attempt:\n");
538→                message.push_str(&attempt.details);
539→            }
540→            return Err(Error::LaunchFailed(message));
541→        }
542→
543→        let selected =
544→            match crate::detect::pick_browser(&detection.browsers, Some(requested_browser)) {
545→                Some(browser) => browser,
546→                None => {
547→                    let installed = crate::detect::installed_browser_labels(&detection.browsers);
548→                    let installed_list = if installed.is_empty() {
549→                        "none".to_string()
550→                    } else {
551→                        installed.join(", ")
552→                    };
553→                    return Err(Error::LaunchFailed(format!(
554→                        "requested browser '{}' is not installed. Installed browsers: {}",
555→                        requested_browser, installed_list
556→                    )));
557→                },
558→            };
559→
560→        let mut builder = CdpBrowserConfig::builder();
561→
562→        // with_head() shows the browser window (non-headless mode)
563→        // By default chromiumoxide runs headless, so we only call with_head() when NOT headless
564→        if !self.config.headless {
565→            builder = builder.with_head();
566→        }
567→
568→        info!(
569→            session_id,
570→            viewport_width = self.config.viewport_width,
571→            viewport_height = self.config.viewport_height,
572→            device_scale_factor = self.config.device_scale_factor,
573→            headless = self.config.headless,
574→            "configuring browser viewport"
575→        );
576→
577→        builder = builder
578→            .viewport(chromiumoxide::handler::viewport::Viewport {
579→                width: self.config.viewport_width,
580→                height: self.config.viewport_height,
581→                device_scale_factor: Some(self.config.device_scale_factor),
582→                emulating_mobile: false,
583→                is_landscape: true,
584→                has_touch: false,
585→            })
586→            .request_timeout(Duration::from_millis(self.config.navigation_timeout_ms));
587→
588→        // User agent can be set via Chrome arg instead of builder method
589→        if let Some(ref ua) = self.config.user_agent {
590→            builder = builder.arg(format!("--user-agent={ua}"));
591→        }
592→        builder = builder.chrome_executable(selected.path.clone());
593→
594→        for arg in &self.config.chrome_args {
595→            builder = builder.arg(arg);
596→        }
597→
598→        // Set persistent profile directory if configured
599→        if let Some(ref profile_path) = self.config.resolved_profile_dir() {
600→            if let Err(e) = std::fs::create_dir_all(profile_path) {
601→                warn!(
602→                    path = %profile_path.display(),
603→                    error = %e,
604→                    "failed to create browser profile directory, falling back to ephemeral"
605→                );
606→            } else {
607→                info!(
608→                    path = %profile_path.display(),
609→                    "using persistent browser profile"
610→                );
611→                builder = builder.user_data_dir(profile_path);
612→            }
613→        }
614→
615→        // Additional security/sandbox args for headless
616→        builder = builder
617→            .arg("--disable-gpu")
618→            .arg("--disable-dev-shm-usage")
619→            .arg("--disable-software-rasterizer")
620→            .arg("--no-sandbox")
621→            .arg("--disable-setuid-sandbox");
622→
623→        // Auto-inject low-memory flags on constrained systems
624→        if self.config.low_memory_threshold_mb > 0 {
625→            let mut sys = System::new();
626→            sys.refresh_memory();
627→            let total_mb = sys.total_memory() / (1024 * 1024);
628→            let extra = low_memory_chrome_args(total_mb, self.config.low_memory_threshold_mb);
629→            if !extra.is_empty() {
630→                info!(
631→                    total_mb,
632→                    threshold = self.config.low_memory_threshold_mb,
633→                    "low memory detected, adding constrained Chrome flags"
634→                );
635→                for arg in extra {
636→                    builder = builder.arg(*arg);
637→                }
638→            }
639→        }
640→
641→        let config = builder
642→            .build()
643→            .map_err(|e| Error::LaunchFailed(format!("failed to build browser config: {e}")))?;
644→
645→        let (browser, mut handler) = Browser::launch(config).await.map_err(|e| {
646→            // Include install instructions in launch failure messages
647→            let install_hint = crate::detect::install_instructions();
648→            Error::LaunchFailed(format!("browser launch failed: {e}\n\n{install_hint}"))
649→        })?;
650→
651→        info!(
652→            session_id,
653→            browser = %selected.kind,
654→            path = %selected.path.display(),
655→            "launched host browser executable"
656→        );
657→
658→        // Spawn handler to process browser events
659→        let session_id_clone = session_id.to_string();
660→        tokio::spawn(async move {
661→            while let Some(event) = handler.next().await {
662→                debug!(session_id = session_id_clone, ?event, "browser event");
663→            }
664→        });
665→
666→        Ok(BrowserInstance {
667→            browser,
668→            pages: HashMap::new(),
669→            last_used: Instant::now(),
670→            created_at: Instant::now(),
671→            sandboxed: false,
672→            container: None,
673→        })
674→    }
675→}
