677→impl Drop for BrowserPool {
678→    fn drop(&mut self) {
679→        let instances = self.instances.get_mut();
680→        let count = instances.len();
681→        if count > 0 {
682→            info!(
683→                count,
684→                "browser pool dropping, stopping remaining containers"
685→            );
686→        }
687→    }
688→}
