690→/// Generate a random session ID.
691→fn generate_session_id() -> String {
692→    use rand::Rng;
693→    let mut rng = rand::rng();
694→    let id: u64 = rng.random();
695→    format!("browser-{:016x}", id)
696→}
697→
698→/// Sanitize a session identifier to a filesystem-safe single path segment.
699→fn sanitize_session_component(session_id: &str) -> String {
700→    let sanitized: String = session_id
701→        .chars()
702→        .map(|ch| match ch {
703→            'a'..='z' | 'A'..='Z' | '0'..='9' | '-' | '_' => ch,
704→            _ => '_',
705→        })
706→        .collect();
707→
708→    if sanitized.is_empty() {
709→        return "session".to_string();
710→    }
711→
712→    sanitized
713→}
714→
715→/// Derive a per-session sandbox profile directory from a configured profile root.
716→fn sandbox_profile_dir(profile_root: Option<PathBuf>, session_id: &str) -> Option<PathBuf> {
717→    profile_root.map(|root| {
718→        root.join("sandbox")
719→            .join(sanitize_session_component(session_id))
720→    })
721→}
722→
723→/// Make a directory world-accessible so container processes (which run as a
724→/// different uid, e.g. uid 999 in browserless/chrome) can read and write it.
725→///
726→/// On Unix this sets mode `0o777`. On non-Unix platforms this is a no-op
727→/// because container runtimes there (e.g. Apple Container) handle permission
728→/// mapping differently.
729→#[cfg(unix)]
730→fn set_container_dir_permissions(dir: &std::path::Path) {
731→    use std::os::unix::fs::PermissionsExt;
732→    if let Err(e) = std::fs::set_permissions(dir, std::fs::Permissions::from_mode(0o777)) {
733→        warn!(
734→            path = %dir.display(),
735→            error = %e,
736→            "failed to set browser profile directory permissions"
737→        );
738→    }
739→}
740→
741→#[cfg(not(unix))]
742→fn set_container_dir_permissions(_dir: &std::path::Path) {}
