 87→    /// Handle a browser request.
 88→    pub async fn handle_request(&self, request: BrowserRequest) -> BrowserResponse {
 89→        if !self.config.enabled {
 90→            return BrowserResponse::error(
 91→                request.session_id.unwrap_or_default(),
 92→                "browser support is disabled",
 93→                0,
 94→            );
 95→        }
 96→
 97→        // Determine sandbox mode from request (defaults to false/host)
 98→        let sandbox = request.sandbox.unwrap_or(false);
 99→
100→        // Log the action with execution mode for visibility
101→        let mode = if sandbox {
102→            "sandbox"
103→        } else {
104→            "host"
105→        };
106→        info!(
107→            action = %request.action,
108→            session_id = request.session_id.as_deref().unwrap_or("(new)"),
109→            browser = ?request.browser,
110→            execution_mode = mode,
111→            sandbox_image = %self.config.sandbox_image,
112→            "executing browser action"
113→        );
114→
115→        let start = Instant::now();
116→        let timeout_duration = Duration::from_millis(request.timeout_ms);
117→
118→        match timeout(
119→            timeout_duration,
120→            self.execute_action(
121→                request.session_id.as_deref(),
122→                request.action,
123→                sandbox,
124→                request.browser,
125→            ),
126→        )
127→        .await
128→        {
129→            Ok(result) => {
130→                let duration_ms = start.elapsed().as_millis() as u64;
131→                match result {
132→                    Ok((session_id, response)) => {
133→                        let mut resp = response;
134→                        resp.duration_ms = duration_ms;
135→                        resp.session_id = session_id;
136→                        resp
137→                    },
138→                    Err(e) => {
139→                        #[cfg(feature = "metrics")]
140→                        moltis_metrics::counter!(
141→                            moltis_metrics::browser::ERRORS_TOTAL,
142→                            "type" => e.to_string()
143→                        )
144→                        .increment(1);
145→
146→                        BrowserResponse::error(
147→                            request.session_id.unwrap_or_default(),
148→                            e.to_string(),
149→                            duration_ms,
150→                        )
151→                    },
152→                }
153→            },
154→            Err(_) => {
155→                #[cfg(feature = "metrics")]
156→                moltis_metrics::counter!(
157→                    moltis_metrics::browser::ERRORS_TOTAL,
158→                    "type" => "timeout"
159→                )
160→                .increment(1);
161→
162→                BrowserResponse::error(
163→                    request.session_id.unwrap_or_default(),
164→                    format!("operation timed out after {}ms", request.timeout_ms),
165→                    request.timeout_ms,
166→                )
167→            },
168→        }
169→    }
