171→    /// Clean up a session whose CDP connection has died and return an
172→    /// actionable error the agent can act on.
173→    async fn cleanup_stale_session(&self, session_id: &str, action: &str) -> Error {
174→        warn!(
175→            session_id,
176→            action, "browser connection dead, closing stale session"
177→        );
178→        let _ = self.pool.close_session(session_id).await;
179→        Error::ConnectionClosed(format!(
180→            "Browser session {session_id} lost its connection during {action}. \
181→             Please navigate to the page again to get a fresh session."
182→        ))
