193→        // Navigate has its own retry-with-fresh-session logic, so handle it
194→        // separately to avoid double-cleanup.
195→        if let BrowserAction::Navigate { ref url } = action {
196→            return self.navigate(session_id, url, sandbox, browser).await;
197→        }
198→
199→        let action_name = action.to_string();
200→
201→        let result = match action {
202→            BrowserAction::Navigate { .. } => unreachable!(),
203→            BrowserAction::Screenshot {
204→                full_page,
205→                highlight_ref,
206→            } => {
207→                self.screenshot(session_id, full_page, highlight_ref, sandbox, browser)
208→                    .await
209→            },
210→            BrowserAction::Snapshot => self.snapshot(session_id, sandbox, browser).await,
211→            BrowserAction::Click { ref_ } => self.click(session_id, ref_, sandbox).await,
212→            BrowserAction::Type { ref_, text } => {
213→                self.type_text(session_id, ref_, &text, sandbox).await
214→            },
215→            BrowserAction::Scroll { ref_, x, y } => {
216→                self.scroll(session_id, ref_, x, y, sandbox).await
217→            },
218→            BrowserAction::Evaluate { code } => self.evaluate(session_id, &code, sandbox).await,
219→            BrowserAction::Wait {
220→                selector,
221→                ref_,
222→                timeout_ms,
223→            } => {
224→                self.wait(session_id, selector, ref_, timeout_ms, sandbox)
225→                    .await
226→            },
227→            BrowserAction::GetUrl => self.get_url(session_id, sandbox).await,
228→            BrowserAction::GetTitle => self.get_title(session_id, sandbox).await,
229→            BrowserAction::Back => self.go_back(session_id, sandbox).await,
230→            BrowserAction::Forward => self.go_forward(session_id, sandbox).await,
231→            BrowserAction::Refresh => self.refresh(session_id, sandbox).await,
232→            BrowserAction::Close => self.close(session_id, sandbox).await,
233→            BrowserAction::StartScreencast {
234→                quality,
235→                max_width,
236→                max_height,
237→            } => {
238→                self.start_screencast(session_id, sandbox, browser, quality, max_width, max_height)
