413→function BrowserPage() {
414→	return html`<div class="flex-1 flex flex-col min-w-0 p-4 gap-3 overflow-y-auto">
415→		<div class="flex items-center justify-between">
416→			<h2 class="text-base font-medium text-[var(--text-strong)]">Browser Sessions</h2>
417→			<button class="provider-btn-secondary text-xs px-2 py-1" onClick=${fetchSessions}>
418→				Refresh
419→			</button>
420→		</div>
421→
422→		<div class="text-xs text-[var(--muted)] max-w-form">
423→			View and interact with browser sessions created by agents. Click "View" to see the
424→			browser screen via CDP screencast, and interact with mouse/keyboard to log in to
425→			websites. Use "Export Cookies" to copy the authenticated session for automation.
426→		</div>
427→
428→		<div class="flex flex-col lg:flex-row gap-4 flex-1 min-h-0">
429→			<div class="lg:w-80 shrink-0">
430→				<${SessionList} />
431→			</div>
432→			<div class="flex-1 flex flex-col min-w-0">
433→				<${NavigateBar} />
434→				<${BrowserCanvas} />
435→			</div>
436→		</div>
437→	</div>`;
