441→
442→export function initBrowser(container) {
443→	containerEl = container;
444→	render(html`<${BrowserPage} />`, container);
445→}
446→
447→export function teardownBrowser() {
448→	stopFrameListener();
449→	if (containerEl) {
450→		render(null, containerEl);
451→		containerEl = null;
452→	}
453→	screencasting.value = false;
454→	activeSession.value = null;
455→	frameData.value = null;
456→}
