 47→impl From<ServiceError> for moltis_protocol::ErrorShape {
 48→    fn from(err: ServiceError) -> Self {
 49→        let code = match &err {
 50→            ServiceError::Forbidden { .. } => moltis_protocol::error_codes::FORBIDDEN,
 51→            _ => moltis_protocol::error_codes::UNAVAILABLE,
 52→        };
 53→        Self::new(code, err.to_string())
 54→    }
 55→}
