 943→            .map_err(|e| Error::Cdp(format!("failed to get cookies: {e}")))?;
 944→
 945→        let cookies: Vec<ExportedCookie> = result
 946→            .cookies
 947→            .clone()
 948→            .into_iter()
 949→            .filter(|c| {
 950→                domain
 951→                    .as_ref()
 952→                    .is_none_or(|d| c.domain.contains(d.as_str()))
 953→            })
 954→            .map(|c| ExportedCookie {
 955→                name: c.name,
 956→                value: c.value,
 957→                domain: c.domain,
 958→                path: c.path,
 959→                secure: c.secure,
 960→                http_only: c.http_only,
 961→                expires: c.expires,
 962→                same_site: c.same_site.map(|s| format!("{s:?}")).unwrap_or_default(),
 963→                size: c.size as u32,
 964→            })
 965→            .collect();
 966→
 967→        info!(session_id = sid, count = cookies.len(), "exported cookies");
 968→
 969→        Ok((
 970→            sid.clone(),
 971→            BrowserResponse::success(sid, 0, sandbox).with_cookies(cookies),
 972→        ))
 973→    }
