 975→    /// Import cookies into the browser session.
 976→    async fn import_cookies(
 977→        &self,
 978→        session_id: Option<&str>,
 979→        cookies: Vec<crate::types::CookieParam>,
 980→        sandbox: bool,
 981→    ) -> Result<(String, BrowserResponse), Error> {
 982→        use chromiumoxide::cdp::browser_protocol::network::{CookieSameSite, SetCookieParams};
 983→
 984→        let sid = require_session(session_id, "import_cookies")?;
 985→        let page = self.pool.get_page(&sid).await?;
 986→
 987→        for cookie in &cookies {
 988→            let mut params = SetCookieParams::builder()
 989→                .name(&cookie.name)
 990→                .value(&cookie.value);
 991→
 992→            if let Some(ref domain) = cookie.domain {
 993→                params = params.domain(domain);
 994→            }
 995→            if let Some(ref path) = cookie.path {
 996→                params = params.path(path);
 997→            }
 998→            if cookie.secure {
 999→                params = params.secure(true);
1000→            }
1001→            if cookie.http_only {
1002→                params = params.http_only(true);
1003→            }
1004→            if let Some(expires) = cookie.expires {
1005→                use chromiumoxide::cdp::browser_protocol::network::TimeSinceEpoch;
1006→                params = params.expires(TimeSinceEpoch::new(expires));
1007→            }
1008→            if let Some(ref ss) = cookie.same_site {
1009→                let same_site = match ss.to_lowercase().as_str() {
1010→                    "strict" => CookieSameSite::Strict,
1011→                    "lax" => CookieSameSite::Lax,
1012→                    _ => CookieSameSite::None,
1013→                };
1014→                params = params.same_site(same_site);
1015→            }
1016→
1017→            let cmd = params.build().map_err(|e| Error::Cdp(e.to_string()))?;
1018→            page.execute(cmd)
1019→                .await
1020→                .map_err(|e| Error::Cdp(format!("failed to set cookie '{}': {e}", cookie.name)))?;
1021→        }
1022→
1023→        info!(session_id = sid, count = cookies.len(), "imported cookies");
1024→
1025→        Ok((sid.clone(), BrowserResponse::success(sid, 0, sandbox)))
1026→    }
