1125→/// Validate a URL before attempting navigation.
1126→///
1127→/// Checks for:
1128→/// - Valid URL structure (can be parsed)
1129→/// - Allowed schemes (http, https)
1130→/// - Not obviously malformed (LLM garbage in path)
1131→fn validate_url(url: &str) -> Result<(), Error> {
1132→    // Check if URL is empty
1133→    if url.is_empty() {
1134→        return Err(Error::InvalidAction("URL cannot be empty".to_string()));
1135→    }
1136→
1137→    // Parse the URL
1138→    let parsed = url::Url::parse(url)
1139→        .map_err(|e| Error::InvalidAction(format!("invalid URL '{}': {}", truncate_url(url), e)))?;
1140→
1141→    // Check scheme
1142→    match parsed.scheme() {
1143→        "http" | "https" => {},
1144→        scheme => {
1145→            return Err(Error::InvalidAction(format!(
1146→                "unsupported URL scheme '{}', only http/https allowed",
1147→                scheme
1148→            )));
1149→        },
1150→    }
1151→
1152→    // Check for obviously malformed URLs (LLM garbage)
1153→    // Check the original URL string (before normalization) to catch garbage
1154→    let suspicious_patterns = [
1155→        "}}}",           // JSON garbage
1156→        "]}",            // JSON array closing
1157→        "}<",            // Mixed JSON/XML
1158→        "assistant to=", // LLM prompt leakage
1159→        "functions.",    // LLM function call leakage (e.g., "functions.browser")
1160→    ];
1161→
1162→    for pattern in suspicious_patterns {
1163→        if url.contains(pattern) {
1164→            warn!(
1165→                url = %truncate_url(url),
1166→                pattern = pattern,
1167→                "rejecting URL with suspicious pattern (likely LLM garbage)"
1168→            );
1169→            return Err(Error::InvalidAction(format!(
1170→                "URL contains invalid characters or LLM garbage: '{}'",
1171→                truncate_url(url)
1172→            )));
1173→        }
1174→    }
1175→
1176→    Ok(())
1177→}
1178→
1179→/// Truncate a URL for error messages (to avoid huge garbage URLs in logs).
1180→fn truncate_url(url: &str) -> String {
1181→    if url.len() > 100 {
1182→        format!("{}...", &url[..url.floor_char_boundary(100)])
1183→    } else {
1184→        url.to_string()
1185→    }
1186→}
