 23→
 24→async function browserAction(params) {
 25→	var res = await fetch("/api/browser/action", {
 26→		method: "POST",
 27→		headers: { "Content-Type": "application/json" },
 28→		body: JSON.stringify(params),
 29→	});
 30→	if (!res.ok) {
 31→		var err = await res.json().catch(() => ({ error: "request failed" }));
 32→		throw new Error(err.error || err.code || "browser action failed");
 33→	}
 34→	return res.json();
 35→}
 36→
 37→async function fetchSessions() {
 38→	loading.value = true;
 39→	try {
 40→		var res = await fetch("/api/browser/sessions");
 41→		if (res.ok) {
 42→			var data = await res.json();
 43→			sessions.value = data.sessions || [];
 44→		}
 45→	} catch (e) {
 46→		console.error("Failed to fetch browser sessions:", e);
 47→	} finally {
 48→		loading.value = false;
 49→	}
 50→}
