128→async function exportCookies(sessionId) {
129→	try {
130→		var res = await browserAction({
131→			session_id: sessionId,
132→			action: "export_cookies",
133→		});
134→		if (res.cookies && res.cookies.length > 0) {
135→			var text = JSON.stringify(res.cookies, null, 2);
136→			await navigator.clipboard.writeText(text);
137→			showToast(`${res.cookies.length} cookies copied to clipboard`);
138→		} else {
