160→// ── Mouse/keyboard input relay ──────────────────────────────
161→
162→function relayMouseEvent(e, canvas) {
163→	if (!(activeSession.value && screencasting.value)) return;
164→	var rect = canvas.getBoundingClientRect();
165→	var meta = frameMeta.value;
166→	if (!meta) return;
167→
168→	// Translate canvas coordinates to browser viewport coordinates
169→	var scaleX = meta.device_width / rect.width;
170→	var scaleY = meta.device_height / rect.height;
171→	var x = (e.clientX - rect.left) * scaleX;
172→	var y = (e.clientY - rect.top) * scaleY;
173→
174→	var eventType;
175→	switch (e.type) {
176→		case "mousedown":
177→			eventType = "mousePressed";
178→			break;
179→		case "mouseup":
180→			eventType = "mouseReleased";
181→			break;
182→		case "mousemove":
183→			eventType = "mouseMoved";
184→			break;
185→		default:
186→			return;
187→	}
188→
189→	var button = ["left", "middle", "right"][e.button] || "left";
190→
191→	// Fire and forget — don't await for mouse events
192→	browserAction({
193→		session_id: activeSession.value,
194→		action: "mouse_input",
195→		x: x,
196→		y: y,
197→		event_type: eventType,
198→		button: button,
199→		click_count: e.type === "mousedown" ? e.detail || 1 : 1,
200→	}).catch(() => {});
201→}
202→
203→function relayKeyEvent(e) {
204→	if (!(activeSession.value && screencasting.value)) return;
205→	e.preventDefault();
206→
207→	var eventType = e.type === "keydown" ? "keyDown" : "keyUp";
208→	var modifiers = 0;
209→	if (e.altKey) modifiers |= 1;
210→	if (e.ctrlKey) modifiers |= 2;
211→	if (e.metaKey) modifiers |= 4;
212→	if (e.shiftKey) modifiers |= 8;
213→
214→	browserAction({
215→		session_id: activeSession.value,
216→		action: "keyboard_input",
217→		event_type: eventType,
218→		key: e.key,
219→		code: e.code,
220→		text: e.key.length === 1 ? e.key : undefined,
221→		modifiers: modifiers || undefined,
222→	}).catch(() => {});
223→}
