299→function formatDuration(secs) {
300→	if (secs < 60) return `${secs}s`;
301→	if (secs < 3600) return `${Math.floor(secs / 60)}m`;
302→	return `${Math.floor(secs / 3600)}h ${Math.floor((secs % 3600) / 60)}m`;
303→}
