1122→pub async fn api_browser_action_handler(
1123→    State(state): State<AppState>,
1124→    Json(body): Json<serde_json::Value>,
1125→) -> Response {
1126→    // Peek at the action to know if we need to start a frame relay afterwards.
1127→    let is_start_screencast = body
1128→        .get("action")
1129→        .and_then(|v| v.as_str())
1130→        .is_some_and(|a| a == "start_screencast");
1131→    let session_id = body
1132→        .get("session_id")
1133→        .and_then(|v| v.as_str())
1134→        .map(String::from);
1135→
1136→    match state.gateway.services.browser.request(body).await {
1137→        Ok(result) => {
1138→            // If we just started a screencast, spawn a relay task that
1139→            // broadcasts frames to all WebSocket clients.
1140→            if is_start_screencast {
1141→                if let Some(sid) = session_id {
1142→                    spawn_screencast_relay(state, &sid).await;
1143→                }
1144→            }
1145→            (StatusCode::OK, Json(result)).into_response()
1146→        },
1147→        Err(e) => api_error_response(
1148→            StatusCode::INTERNAL_SERVER_ERROR,
1149→            BROWSER_REQUEST_FAILED,
1150→            e.to_string(),
1151→        ),
1152→    }
1153→}
