1155→/// Spawn a background task that subscribes to screencast frames for the given
1156→/// session and broadcasts each frame as a `browser.screencast.frame` event to
1157→/// all connected WebSocket clients.
1158→async fn spawn_screencast_relay(state: AppState, session_id: &str) {
1159→    let Some(mut rx) = state
1160→        .gateway
1161→        .services
1162→        .browser
1163→        .subscribe_screencast(session_id)
1164→        .await
1165→    else {
1166→        return;
1167→    };
1168→
1169→    let gateway = Arc::clone(&state.gateway);
1170→    tokio::spawn(async move {
1171→        loop {
1172→            match rx.recv().await {
1173→                Ok(payload) => {
1174→                    moltis_gateway::broadcast::broadcast(
1175→                        &gateway,
1176→                        "browser.screencast.frame",
1177→                        payload,
1178→                        moltis_gateway::broadcast::BroadcastOpts {
1179→                            drop_if_slow: true,
