async function stopScreencast(sessionId) {
	try {
		await browserAction({
			session_id: sessionId,
			action: "stop_screencast",
		});
	} catch {
		// best effort
	}
	screencasting.value = false;
	activeSession.value = null;
	frameData.value = null;
	stopFrameListener();
	showToast("Screencast stopped");
}

